import type { DurationKey, SpellType } from '../schema'

/** Magia pré-criada do catálogo (semeada do Livro Básico). */
export interface CatalogSpell {
  id: string
  name: string
  circle: number
  type: Exclude<SpellType, ''>
  /** Escola de magia (Abjuração, Evocação, Necromancia…). */
  school: string
  /** Execução (ação de conjuração). */
  action: string
  /** Alcance (Pessoal, Toque, Curto, Médio, Longo). */
  range: string
  /** Alvo, Área ou Efeito. */
  target: string
  duration: DurationKey
  /** Resistência (ex.: "Vontade anula"). Vazio = nenhuma. */
  resistance: string
  /** Descrição do efeito (parágrafo principal, sem os aprimoramentos). */
  description: string
}

/** Escolas de magia do T20 (para o filtro do catálogo). */
export const SPELL_SCHOOLS = [
  'Abjuração',
  'Adivinhação',
  'Convocação',
  'Encantamento',
  'Evocação',
  'Ilusão',
  'Necromancia',
  'Transmutação',
] as const

/**
 * Catálogo de magias de 1º círculo (arcanas, divinas e universais) do Livro
 * Básico. Os campos (tipo, escola, execução, alcance, alvo/área, duração,
 * resistência, descrição) vêm da descrição de cada magia. Durações fora do enum
 * (1 turno, permanente) são mapeadas para o valor mais próximo (Rodada/Dia). A
 * descrição é o parágrafo principal, sem os aprimoramentos (+PM).
 */
export const SPELL_CATALOG: CatalogSpell[] = [
  { id: 'abencoar-alimentos', name: 'Abençoar Alimentos', circle: 1, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Curto', target: 'alimento para 1 criatura', duration: 'Cena', resistance: '', description: 'Você purifica e abençoa uma porção de comida ou dose de bebida. Isso torna um alimento sujo, estragado ou envenenado próprio para consumo. Além disso, se for consumido até o final da duração, o alimento oferece 5 PV temporários ou 1 PM temporário (além de quaisquer bônus que já oferecesse). Bônus de alimentação duram um dia e cada personagem só pode receber um bônus de alimentação por dia.' },
  { id: 'acalmar-animal', name: 'Acalmar Animal', circle: 1, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 animal', duration: 'Cena', resistance: 'Vontade anula', description: 'O animal fica prestativo em relação a você. Ele não fica sob seu controle, mas percebe suas palavras e ações da maneira mais favorável possível. Você recebe +10 nos testes de Adestramento e Diplomacia que fizer contra o animal. Um alvo hostil ou que esteja envolvido em um combate recebe +5 em seu teste de resistência. Se você ou seus aliados tomarem qualquer ação hostil contra o alvo, a magia é dissipada e ele retorna à atitude que tinha antes (ou piorada, de acordo com o mestre). Se tratar bem o alvo, a atitude pode permanecer mesmo após o término da magia.' },
  { id: 'adaga-mental', name: 'Adaga Mental', circle: 1, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Instantânea', resistance: 'Vontade parcial', description: 'Você manifesta e dispara uma adaga imaterial contra a mente do alvo, que sofre 2d6 pontos de dano psíquico e fica atordoado por uma rodada. Se passar no teste de resistência, sofre apenas metade do dano e evita a condição. Uma criatura só pode ficar atordoada por esta magia uma vez por cena.' },
  { id: 'alarme', name: 'Alarme', circle: 1, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Curto', target: 'esfera com 9m de raio', duration: 'Dia', resistance: '', description: 'Você cria uma barreira protetora invisível que detecta qualquer criatura que tocar ou entrar na área protegida. Ao lançar a magia, você pode escolher quais criaturas podem entrar na área sem ativar seus efeitos. Alarme pode emitir um aviso telepático ou sonoro, decidido quando a magia é lançada. Um aviso telepático alerta apenas você, inclusive acordando-o se estiver dormindo, mas apenas se estiver a até 1km da área protegida. Um aviso sonoro alerta todas as criaturas em alcance longo.' },
  { id: 'amedrontar', name: 'Amedrontar', circle: 1, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 animal ou humanoide', duration: 'Cena', resistance: 'Vontade parcial', description: 'O alvo é envolvido por energias sombrias e assustadoras. Se falhar na resistência, fica apavorado por 1 rodada, depois abalado. Se passar, fica abalado por 1d4 rodadas.' },
  { id: 'area-escorregadia', name: 'Área Escorregadia', circle: 1, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'quadrado de 3m ou 1 objeto', duration: 'Cena', resistance: 'Reflexos (veja texto)', description: 'Esta magia recobre uma superfície com uma substância gordurosa e escorregadia. Criaturas na área devem passar na resistência para não cair. Nas rodadas seguintes, criaturas que tentem movimentar-se pela área devem fazer testes de Acrobacia para equilíbrio (CD 10). Área Escorregadia pode tornar um item escorregadio. Uma criatura segurando um objeto afetado deve passar na resistência para não deixar o item cair cada vez que usá-lo.' },
  { id: 'arma-espiritual', name: 'Arma Espiritual', circle: 1, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Você invoca a arma preferida de sua divindade (caso sua divindade possua uma), que surge flutuando a seu lado. Uma vez por rodada, quando você sofre um ataque corpo a corpo, pode usar uma reação para que a arma cause automaticamente 2d6 pontos de dano do tipo da arma — por exemplo, uma espada longa causa dano de corte — no oponente que fez o ataque. Esta magia se dissipa se você morrer.' },
  { id: 'arma-magica', name: 'Arma Mágica', circle: 1, type: 'Universal', school: 'Transmutação', action: 'Padrão', range: 'Toque', target: '1 arma empunhada', duration: 'Cena', resistance: '', description: 'A arma é considerada mágica e fornece +1 nos testes de ataque e rolagens de dano (isso conta como um bônus de encanto). Caso você esteja empunhando a arma, pode usar seu atributo-chave de magias em vez do atributo original nos testes de ataque (não cumulativo com efeitos que somam este atributo).' },
  { id: 'armadura-arcana', name: 'Armadura Arcana', circle: 1, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Esta magia cria uma película protetora invisível, mas tangível, fornecendo +5 na Defesa. Esse bônus é cumulativo com outras magias, mas não com bônus fornecido por armaduras.' },
  { id: 'armamento-da-natureza', name: 'Armamento da Natureza', circle: 1, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Toque', target: '1 arma (veja texto)', duration: 'Cena', resistance: '', description: 'Você fortalece uma arma mundana primitiva (sem custo em T$, como bordão, clava, funda ou tacape), uma arma natural ou um ataque desarmado. O dano da arma aumenta em um passo e ela é considerada mágica. Ao lançar a magia, você pode mudar o tipo de dano da arma (escolhendo entre corte, impacto ou perfuração).' },
  { id: 'aviso', name: 'Aviso', circle: 1, type: 'Universal', school: 'Adivinhação', action: 'Movimento', range: 'Longo', target: '1 criatura', duration: 'Instantânea', resistance: '', description: 'Envia um aviso telepático para uma criatura, mesmo que não possa vê-la nem tenha linha de efeito. Escolha um: Alerta: o alvo recebe +5 em seu próximo teste de Iniciativa e de Percepção dentro da cena. Mensagem: o alvo recebe uma mensagem sua de até 25 palavras. Vocês devem ter um idioma em comum para o alvo poder entendê-lo. Localização: o alvo sabe onde você está naquele momento. Se você mudar de posição, ele não saberá.' },
  { id: 'bencao', name: 'Bênção', circle: 1, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: 'aliados', duration: 'Cena', resistance: '', description: 'Abençoa seus aliados, que recebem +1 em testes de ataque e rolagens de dano. Bênção anula Perdição.' },
  { id: 'caminhos-da-natureza', name: 'Caminhos da Natureza', circle: 1, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'criaturas escolhidas', duration: 'Dia', resistance: '', description: 'Você invoca espíritos da natureza, pedindo que eles abram seu caminho. As criaturas afetadas recebem deslocamento +3m e ignoram penalidades por terreno difícil em terrenos naturais.' },
  { id: 'comando', name: 'Comando', circle: 1, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 humanoide', duration: 'Rodada', resistance: 'Vontade anula', description: 'Você dá uma ordem irresistível, que o alvo deve ser capaz de ouvir (mas não precisa entender). Se falhar na resistência, ele deve obedecer ao comando em seu próprio turno da melhor maneira possível. Escolha um dos efeitos. Fuja: o alvo gasta seu turno se afastando de você (usando todas as suas ações). Largue: o alvo solta quaisquer itens que esteja segurando e não pode pegá-los novamente até o início de seu próximo turno. Como esta é uma ação livre, ele ainda pode executar outras ações (exceto pegar aquilo que largou). Pare: o alvo fica pasmo (apenas uma vez por cena). Senta: com uma ação livre, o alvo senta no chão (se estava pendurado ou voando, desce até o chão). Ele pode fazer outras ações, mas não se levantar até o início de seu próximo turno. Venha: o alvo gasta seu turno se aproximando de você (usando todas as suas ações).' },
  { id: 'compreensao', name: 'Compreensão', circle: 1, type: 'Universal', school: 'Adivinhação', action: 'Padrão', range: 'Toque', target: '1 criatura ou texto', duration: 'Cena', resistance: 'Vontade anula (veja descrição)', description: 'Essa magia lhe confere compreensão sobrenatural. Você pode tocar um texto e entender as palavras mesmo que não conheça o idioma. Se tocar numa criatura inteligente, pode se comunicar com ela mesmo que não tenham um idioma em comum. Se tocar uma criatura não inteligente, como um animal, pode perceber seus sentimentos. Você também pode gastar uma ação de movimento para ouvir os pensamentos de uma criatura tocada, mas um alvo involuntário tem direito a um teste de Vontade para proteger seus pensamentos e evitar este efeito.' },
  { id: 'concentracao-de-combate', name: 'Concentração de Combate', circle: 1, type: 'Arcana', school: 'Adivinhação', action: 'Livre', range: 'Pessoal', target: 'você', duration: 'Rodada', resistance: '', description: 'Você amplia sua percepção, antecipando movimentos dos inimigos e achando brechas em sua defesa. Quando faz um teste de ataque, você rola dois dados e usa o melhor resultado.' },
  { id: 'conjurar-monstro', name: 'Conjurar Monstro', circle: 1, type: 'Arcana', school: 'Convocação', action: 'Completa', range: 'Curto', target: '1 criatura conjurada', duration: 'Sustentada', resistance: '', description: 'Você conjura um monstro Pequeno que ataca seus inimigos. Você escolhe a aparência do monstro e o tipo de dano que ele pode causar, entre corte, impacto e perfuração. No entanto, ele não é uma criatura real, e sim um construto feito de energia. Se for destruído, ou quando a magia acaba, desaparece com um brilho, sem deixar nada para trás. Você só pode ter um monstro conjurado por esta magia por vez. O monstro surge em um espaço desocupado a sua escolha dentro do alcance e age no início de cada um de seus turnos, a partir da próxima rodada. O monstro tem deslocamento 9m e pode fazer uma ação de movimento por rodada. Você pode gastar uma ação padrão para dar uma das seguintes ordens a ele. Mover: o monstro se movimenta o dobro do deslocamento nessa rodada. Atacar: o monstro causa 2d4+2 pontos de dano a uma criatura adjacente. Lançar Magia: o monstro pode servir como ponto de origem para uma magia lançada por você com execução de uma ação padrão ou menor. Você gasta PM normalmente para lançar a magia. O monstro não age sem receber uma ordem. Para efeitos de jogo, o monstro conjurado tem For 2, Des 3 e todos os outros atributos nulos. Ele tem Defesa igual a sua, 20 pontos de vida e usa o seu bônus para teste de Reflexos. Ele é imune a efeitos que pedem um teste de Fortitude ou Vontade.' },
  { id: 'consagrar', name: 'Consagrar', circle: 1, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Longo', target: 'esfera com 9m de raio', duration: 'Dia', resistance: '', description: 'Você enche a área com energia positiva. Pontos de vida curados por efeitos de luz são maximizados dentro da área. Isso também afeta dano causado em mortos-vivos por esses efeitos. Por exemplo, Curar Ferimentos cura automaticamente 18 PV. Esta magia não pode ser lançada em uma área contendo um símbolo visível dedicado a uma divindade que não a sua. Consagrar anula Profanar.' },
  { id: 'controlar-plantas', name: 'Controlar Plantas', circle: 1, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Curto', target: 'quadrado com 9m de lado', duration: 'Cena', resistance: 'Reflexos anula', description: 'Esta magia só pode ser lançada em uma área com vegetação. As plantas se enroscam nas criaturas da área. Aquelas que falharem na resistência ficam enredadas. Uma vítima pode se libertar com uma ação padrão e um teste de Acrobacia ou Atletismo. Além disso, a área é considerada terreno difícil. No início de seus turnos, a vegetação tenta enredar novamente qualquer criatura na área, exigindo um novo teste de Reflexos.' },
  { id: 'criar-elementos', name: 'Criar Elementos', circle: 1, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'elemento escolhido', duration: 'Instantânea', resistance: '', description: 'Você cria uma pequena porção de um elemento, a sua escolha. Os elementos criados são reais, não mágicos. Elementos físicos devem surgir em uma superfície. Em vez de um cubo, pode-se criar objetos simples (sem partes móveis) feitos de gelo, terra ou pedra. Água: enche um recipiente de tamanho Minúsculo (como um odre) com água potável ou cria um cubo de gelo de tamanho Minúsculo. Ar: cria um vento fraco em um quadrado de 1,5m. Isso purifica a área de qualquer gás ou fumaça, ou remove névoa por uma rodada. Fogo: cria uma chama que ilumina como uma tocha. Você pode segurá-la na palma de sua mão sem se queimar, ou fazê-la surgir em um quadrado de 1,5m. Se uma criatura ou objeto estiver no quadrado, sofre 1d6 pontos de dano de fogo; se falhar num teste de Reflexos, fica em chamas. Terra: cria um cubo de tamanho Minúsculo feito de terra, argila ou pedra.' },
  { id: 'criar-ilusao', name: 'Criar Ilusão', circle: 1, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Médio', target: 'ilusão que se estende a até 4 cubos de 1,5m', duration: 'Cena', resistance: 'Vontade desacredita', description: 'Esta magia cria uma ilusão visual (uma criatura, uma parede...) ou sonora (um grito de socorro, um uivo assustador...). A magia cria apenas imagens ou sons simples, com volume equivalente ao tom de voz normal para cada cubo de 1,5m no efeito. Não é possível criar cheiros, texturas ou temperaturas, nem sons complexos, como uma música ou diálogo. Criaturas e objetos atravessam uma ilusão sem sofrer dano, mas a magia pode, por exemplo, esconder uma armadilha ou inimigo. A magia é dissipada se você sair do alcance.' },
  { id: 'curar-ferimentos', name: 'Curar Ferimentos', circle: 1, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: '', description: 'Você canaliza luz que recupera 2d8+2 pontos de vida na criatura tocada.' },
  { id: 'despedacar', name: 'Despedaçar', circle: 1, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Curto', target: '1 criatura ou objeto mundano Pequeno', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Esta magia emite um som alto e agudo. O alvo sofre 1d8+2 pontos de dano de impacto (ou o dobro disso e ignora RD se for um construto ou objeto mundano) e fica atordoado por uma rodada (apenas uma vez por cena). Um teste de Fortitude reduz o dano à metade e evita o atordoamento.' },
  { id: 'detectar-ameacas', name: 'Detectar Ameaças', circle: 1, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Pessoal', target: 'esfera com 18m de raio', duration: 'Cena', resistance: '', description: 'Você recebe uma intuição aguçada sobre perigos ao seu redor. Quando uma criatura hostil ou armadilha entra na área do efeito, você faz um teste de Percepção (CD determinada pelo mestre de acordo com a situação). Se passar, sabe a origem (criatura ou armadilha), direção e distância do perigo. Se falhar, sabe apenas que o perigo existe.' },
  { id: 'disfarce-ilusorio', name: 'Disfarce Ilusório', circle: 1, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: 'Vontade desacredita', description: 'Você muda a aparência do alvo, incluindo seu equipamento. Isso inclui altura, peso, tom de pele, cor de cabelo, timbre de voz etc. O alvo recebe +10 em testes de Enganação para disfarce. O alvo não recebe novas habilidades (você pode ficar parecido com outra raça, mas não ganhará as habilidades dela), nem modifica o equipamento (uma espada longa disfarçada de bordão continua funcionando e causando dano como uma espada).' },
  { id: 'enfeiticar', name: 'Enfeitiçar', circle: 1, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 humanoide', duration: 'Cena', resistance: 'Vontade anula', description: 'O alvo fica enfeitiçado (veja a página 394). Um alvo hostil ou que esteja envolvido em um combate recebe +5 em seu teste de resistência. Se você ou seus aliados tomarem qualquer ação hostil contra o alvo, a magia é dissipada e o alvo retorna à atitude que tinha antes (ou piorada, de acordo com o mestre).' },
  { id: 'escudo-da-fe', name: 'Escudo da Fé', circle: 1, type: 'Divina', school: 'Abjuração', action: 'Reação', range: 'Curto', target: '1 criatura', duration: 'Rodada', resistance: '', description: 'Um escudo místico se manifesta momentaneamente para bloquear um golpe. O alvo recebe +2 na Defesa.' },
  { id: 'escuridao', name: 'Escuridão', circle: 1, type: 'Universal', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 objeto', duration: 'Cena', resistance: 'Vontade anula (veja texto)', description: 'O alvo emana sombras em uma área com 6m de raio. Criaturas dentro da área recebem camuflagem leve por escuridão leve. As sombras não podem ser iluminadas por nenhuma fonte de luz natural. O objeto pode ser guardado (em um bolso, por exemplo) para interromper a escuridão, que voltará a funcionar caso o objeto seja revelado. Se lançar a magia num objeto de uma criatura involuntária, ela tem direito a um teste de Vontade para anulá-la. Escuridão anula Luz.' },
  { id: 'explosao-de-chamas', name: 'Explosão de Chamas', circle: 1, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'cone de 6m', duration: 'Instantânea', resistance: 'Reflexos reduz à metade', description: 'Um leque de chamas irrompe de suas mãos, causando 2d6 pontos de dano de fogo às criaturas na área.' },
  { id: 'imagem-espelhada', name: 'Imagem Espelhada', circle: 1, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Três cópias ilusórias suas aparecem. As duplicatas ficam ao seu redor e imitam suas ações, tornando difícil para um inimigo saber quem atacar. Você recebe +6 na Defesa. Cada vez que um ataque contra você erra, uma das imagens desaparece e o bônus na Defesa diminui em 2. Um oponente deve ver as cópias para ser confundido. Se você estiver invisível, ou o atacante fechar os olhos, você não recebe o bônus (mas o atacante ainda sofre penalidades normais por não enxergar).' },
  { id: 'infligir-ferimentos', name: 'Infligir Ferimentos', circle: 1, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude reduz à metade', description: 'Você canaliza energia negativa contra um alvo, causando 2d8+2 pontos de dano de trevas (ou curando 2d8+2 PV, se for um morto-vivo). Infligir Ferimentos anula Curar Ferimentos.' },
  { id: 'leque-cromatico', name: 'Leque Cromático', circle: 1, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Pessoal', target: 'cone de 4,5m', duration: 'Instantânea', resistance: 'Vontade parcial', description: 'Um cone de luzes brilhantes surge das suas mãos, deixando os animais e humanoides na área atordoados por 1 rodada (apenas uma vez por cena, Vontade anula) e ofuscados pela cena.' },
  { id: 'luz', name: 'Luz', circle: 1, type: 'Universal', school: 'Evocação', action: 'Padrão', range: 'Curto', target: '1 objeto', duration: 'Cena', resistance: 'Vontade anula (veja texto)', description: 'O alvo emite luz (mas não produz calor) em uma área com 6m de raio. O objeto pode ser guardado (em um bolso, por exemplo) para interromper a luz, que voltará a funcionar caso o objeto seja revelado. Se lançar a magia num objeto de uma criatura involuntária, ela tem direito a um teste de Vontade para anulá-la. Luz anula Escuridão.' },
  { id: 'nevoa', name: 'Névoa', circle: 1, type: 'Universal', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'nuvem com 6m de raio e 6m de altura', duration: 'Cena', resistance: '', description: 'Uma névoa espessa eleva-se de um ponto a sua escolha, obscurecendo toda a visão — criaturas a até 1,5m têm camuflagem leve e criaturas a partir de 3m têm camuflagem total. Um vento forte dispersa a névoa em 4 rodadas e um vendaval a dispersa em 1 rodada. Esta magia não funciona sob a água.' },
  { id: 'orientacao', name: 'Orientação', circle: 1, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Rodada', resistance: '', description: 'Em seu próximo teste de perícia, o alvo pode rolar dois dados e ficar com o melhor resultado.' },
  { id: 'perdicao', name: 'Perdição', circle: 1, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: 'criaturas escolhidas', duration: 'Cena', resistance: 'nenhuma', description: 'Amaldiçoa os alvos, que recebem –1 em testes de ataque e rolagens de dano. Perdição anula Bênção.' },
  { id: 'primor-atletico', name: 'Primor Atlético', circle: 1, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você modifica os limites físicos do alvo, que recebe deslocamento +9m e +10 em testes de Atletismo.' },
  { id: 'profanar', name: 'Profanar', circle: 1, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Longo', target: 'esfera com 9m de raio', duration: 'Dia', resistance: '', description: 'Você enche a área com energia negativa. Dano causado por efeitos de trevas é maximizado dentro da área. Isso também afeta PV curados em mortos-vivos por esses efeitos. Esta magia não pode ser lançada em uma área contendo um símbolo visível dedicado a uma divindade que não a sua. Profanar anula Consagrar.' },
  { id: 'protecao-divina', name: 'Proteção Divina', circle: 1, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Esta magia cria uma barreira mística invisível que fornece ao alvo +2 em testes de resistência.' },
  { id: 'queda-suave', name: 'Queda Suave', circle: 1, type: 'Arcana', school: 'Transmutação', action: 'Reação', range: 'Curto', target: '1 criatura ou objeto Grande ou menor', duration: 'Cena', resistance: '', description: 'O alvo cai lentamente. A velocidade da queda é reduzida para 18m por rodada — o suficiente para não causar dano. Como lançar esta magia é uma reação, você pode lançá-la rápido o bastante para salvar a si ou um aliado de quedas inesperadas. Lançada sobre um projétil — como uma flecha ou uma rocha largada do alto de um penhasco —, a magia faz com que ele cause metade do dano normal, devido à lentidão. Queda Suave só funciona em criaturas e objetos em queda livre; a magia não vai frear um golpe de espada ou o mergulho rasante de um atacante voador.' },
  { id: 'raio-do-enfraquecimento', name: 'Raio do Enfraquecimento', circle: 1, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Cena', resistance: 'Fortitude parcial', description: 'Você dispara um raio púrpura que drena as forças do alvo. Se falhar na resistência, o alvo fica fatigado. Se passar, fica vulnerável. Note que, como efeitos de magia não acumulam, lançar esta magia duas vezes contra o mesmo alvo não irá deixá-lo exausto.' },
  { id: 'resistencia-a-energia', name: 'Resistência a Energia', circle: 1, type: 'Universal', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Ao lançar esta magia, escolha entre ácido, eletricidade, fogo, frio, luz ou trevas. O alvo recebe redução de dano 10 contra o tipo de dano escolhido.' },
  { id: 'santuario', name: 'Santuário', circle: 1, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: 'Vontade anula', description: 'Qualquer criatura que tente fazer uma ação hostil contra o alvo deve fazer um teste de Vontade. Se falhar, não consegue, perde a ação e não pode tentar novamente até o fim da cena. Santuário não protege o alvo de efeitos de área. Além disso, o próprio alvo também não pode fazer ações hostis (incluindo forçar outras criaturas a atacá-lo), ou a magia é dissipada — mas pode usar habilidades e magias de cura e suporte, como Curar Ferimentos e Bênção.' },
  { id: 'seta-infalivel-de-talude', name: 'Seta Infalível de Talude', circle: 1, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'criaturas escolhidas', duration: 'Instantânea', resistance: '', description: 'Favorita entre arcanistas iniciantes, esta magia lança duas setas de energia que causam 1d4+1 pontos de dano de essência cada. Você pode lançar as setas em alvos diferentes ou concentrá-las num mesmo alvo. Caso você possua um bônus no dano de magias, como pelo poder Arcano de Batalha, ele é aplicado em apenas uma seta (o bônus vale para a magia, não cada alvo).' },
  { id: 'sono', name: 'Sono', circle: 1, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 humanoide', duration: 'Cena', resistance: 'Vontade parcial', description: 'Um cansaço místico recai sobre o alvo. Se falhar na resistência, ele fica inconsciente e caído ou, se estiver envolvido em combate ou outra situação perigosa, fica exausto por 1 rodada, depois fatigado. Em ambos os casos, se passar, o alvo fica fatigado por 1d4 rodadas.' },
  { id: 'suporte-ambiental', name: 'Suporte Ambiental', circle: 1, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Dia', resistance: '', description: 'Esta magia facilita a sobrevivência em ambientes hostis. O alvo fica imune aos efeitos de calor e frio extremos, pode respirar na água se respirar ar (ou vice-versa) e não sufoca em fumaça densa.' },
  { id: 'teia', name: 'Teia', circle: 1, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'cubo com 6m de lado', duration: 'Cena', resistance: 'Reflexos anula', description: 'Teia cria várias camadas de fibras entrelaçadas e pegajosas na área. Qualquer criatura na área que falhar na resistência fica enredada. Uma vítima pode se libertar com uma ação padrão e um teste de Acrobacia ou Atletismo. A área ocupada por Teia é terreno difícil. A Teia é inflamável. Qualquer ataque que cause dano de fogo destrói as teias por onde passar, libertando as criaturas enredadas mas deixando-as em chamas.' },
  { id: 'toque-chocante', name: 'Toque Chocante', circle: 1, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude reduz à metade', description: 'Arcos elétricos envolvem sua mão, causando 2d8+2 pontos de dano de eletricidade. Se o alvo usa armadura de metal (ou carrega muito metal, a critério do mestre), sofre uma penalidade de –5 no teste de resistência.' },
  { id: 'tranca-arcana', name: 'Tranca Arcana', circle: 1, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 objeto Grande ou menor', duration: 'Dia', resistance: '', description: 'Esta magia tranca uma porta ou outro item que possa ser aberto ou fechado (como um baú, caixa etc.), aumentando a CD de testes de Força ou Ladinagem para abri-lo em +10. Você pode abrir livremente sua própria tranca sem problemas. Componente material: chave de bronze no valor de T$ 25.' },
  { id: 'tranquilidade', name: 'Tranquilidade', circle: 1, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 animal ou humanoide', duration: 'Cena', resistance: 'Vontade parcial', description: 'Você emana ondas de serenidade. Se falhar na resistência, o alvo tem sua atitude mudada para indiferente (veja a página 259) e não pode atacar ou realizar qualquer ação agressiva. Se passar, sofre –2 em testes de ataque. Qualquer ação hostil contra o alvo ou seus aliados dissipa a magia e faz ele retornar à atitude que tinha antes (ou pior, de acordo com o mestre).' },
  { id: 'transmutar-objetos', name: 'Transmutar Objetos', circle: 1, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Toque', target: 'matéria-prima, como madeira, rochas, ossos', duration: 'Cena', resistance: '', description: 'A magia transforma matéria bruta para moldar um novo objeto. Você pode usar matéria-prima mundana para criar um objeto de tamanho Pequeno ou menor e preço máximo de T$ 25, como um balde ou uma espada. O objeto reverte à matéria-prima no final da cena, ou se for tocado por um objeto feito de chumbo. Esta magia não pode ser usada para criar objetos consumíveis, como alimentos ou itens alquímicos, nem objetos com mecanismos complexos, como bestas ou armas de fogo. Transmutar Objetos anula Despedaçar.' },
  { id: 'visao-mistica', name: 'Visão Mística', circle: 1, type: 'Universal', school: 'Adivinhação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Seus olhos brilham com uma luz azul e passam a enxergar auras mágicas. Este efeito é similar ao uso de Misticismo para detectar magia, mas você detecta todas as auras mágicas em alcance médio e recebe todas as informações sobre elas sem gastar ações. Além disso, você pode gastar uma ação de movimento para descobrir se uma criatura que possa perceber em alcance médio é capaz de lançar magias e qual a aura gerada pelas magias de círculo mais alto que ela pode lançar.' },
  { id: 'vitalidade-fantasma', name: 'Vitalidade Fantasma', circle: 1, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Instantânea', resistance: '', description: 'Você suga energia vital da terra, recebendo 2d10 pontos de vida temporários. Os PV temporários desaparecem ao final da cena.' },
  // 2º Círculo
  { id: 'aliado-animal', name: 'Aliado Animal', circle: 2, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 animal prestativo', duration: 'Dia', resistance: '', description: 'Você cria um vínculo mental com um animal prestativo em relação a você. O Aliado Animal obedece a você no melhor de suas capacidades, mesmo que isso arrisque a vida dele. Ele funciona como um parceiro veterano, de um tipo a sua escolha entre ajudante, combatente, fortão, guardião, montaria ou perseguidor.' },
  { id: 'alterar-tamanho', name: 'Alterar Tamanho', circle: 2, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Curto', target: '1 objeto', duration: 'Dia', resistance: '', description: 'Esta magia aumenta ou diminui o tamanho de um item mundano em até três categorias (um objeto Enorme vira Pequeno, por exemplo). Você também pode mudar a consistência do item, deixando-o rígido como pedra ou flexível como seda (isso não altera sua RD ou PV, apenas suas propriedades físicas). Se lançar a magia num objeto de uma criatura involuntária, ela pode fazer um teste de Vontade para anulá-la.' },
  { id: 'amarras-etereas', name: 'Amarras Etéreas', circle: 2, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Cena', resistance: 'Reflexos anula', description: 'Três laços de energia surgem e se enroscam no alvo, deixando-o agarrado. A vítima pode tentar se livrar, gastando uma ação padrão para fazer um teste de Atletismo. Se passar, destrói um laço, mais um laço adicional para cada 5 pontos pelos quais superou a CD. Os laços também podem ser atacados e destruídos: cada um tem Defesa 10, 10 PV, RD 5 e imunidade a dano mágico. Se todos os laços forem destruídos, a magia é dissipada. Por serem feitos de energia, os laços afetam criaturas incorpóreas.' },
  { id: 'aparencia-perfeita', name: 'Aparência Perfeita', circle: 2, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Esta magia lhe concede um rosto idealizado, porte físico garboso, voz melodiosa e olhar sedutor. Caso seu Carisma seja 5 ou mais, você recebe +2 neste atributo. Do contrário, ele se torna 5 (isso conta como um bônus). Além disso, você recebe +5 em Diplomacia e Enganação. Quando a magia acaba, quaisquer observadores percebem a mudança e tendem a suspeitar de você.' },
  { id: 'augurio', name: 'Augúrio', circle: 2, type: 'Divina', school: 'Adivinhação', action: 'Completa', range: 'Pessoal', target: 'você', duration: 'Instantânea', resistance: '', description: 'Esta magia diz se uma ação que você tomará em breve — no máximo uma hora no futuro — trará resultados bons ou ruins. O mestre rola 1d6 em segredo; com um resultado de 2 a 6, a magia funciona e você recebe uma das seguintes respostas: "felicidade" (a ação trará bons resultados); "miséria" (a ação trará maus resultados); "felicidade e miséria" (para ambos) ou "nada" (para ações que não trarão resultados bons ou ruins). Com um resultado 1, a magia falha e oferece o resultado "nada".' },
  { id: 'bola-de-fogo', name: 'Bola de Fogo', circle: 2, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'esfera com 6m de raio', duration: 'Instantânea', resistance: 'Reflexos reduz à metade', description: 'Esta famosa magia de ataque cria uma poderosa explosão, causando 6d6 pontos de dano de fogo em todas as criaturas e objetos livres na área.' },
  { id: 'campo-de-forca', name: 'Campo de Força', circle: 2, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Esta magia cria uma película protetora sobre você. Você recebe 30 pontos de vida temporários.' },
  { id: 'camuflagem-ilusoria', name: 'Camuflagem Ilusória', circle: 2, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'O alvo fica com sua imagem nublada, como se vista através de um líquido, recebendo os efeitos de camuflagem leve.' },
  { id: 'circulo-da-justica', name: 'Círculo da Justiça', circle: 2, type: 'Divina', school: 'Abjuração', action: 'Completa', range: 'Curto', target: 'esfera com 9m de raio', duration: 'Dia', resistance: 'Vontade parcial', description: 'Também conhecida como Lágrimas de Hyninn, esta magia é usada em tribunais e para proteger áreas sensíveis. Criaturas na área sofrem –10 em testes de Acrobacia, Enganação, Furtividade e Ladinagem e não podem mentir deliberadamente — mas podem tentar evitar perguntas que normalmente responderiam com uma mentira (sendo evasivas ou cometendo omissões, por exemplo). Uma criatura que passe na resistência tem as penalidades reduzidas para –5 e pode mentir.' },
  { id: 'condicao', name: 'Condição', circle: 2, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Curto', target: 'até 5 criaturas', duration: 'Cena', resistance: '', description: 'Pela duração da magia, você sabe a posição e status (PV atuais, se estão com uma condição ou sob efeito de magia...) dos alvos. Depois de lançada, a distância dos alvos não importa — a magia só deixa de detectar um alvo se ele morrer ou for para outro plano.' },
  { id: 'conjurar-mortos-vivos', name: 'Conjurar Mortos-Vivos', circle: 2, type: 'Universal', school: 'Necromancia', action: 'Completa', range: 'Curto', target: '6 mortos-vivos', duration: 'Sustentada', resistance: '', description: 'Você conjura seis esqueletos capangas de tamanho Médio feitos de energia negativa em espaços desocupados dentro do alcance. Você pode gastar uma ação de movimento para fazer os mortos-vivos andarem (eles têm deslocamento 9m) ou uma ação padrão para fazê-los causar dano a criaturas adjacentes (1d6+2 pontos de dano de trevas cada). Os esqueletos têm For 2, Des 2, Defesa 18 e todos os outros atributos nulos; eles têm 1 PV e falham automaticamente em qualquer teste de resistência ou oposto, mas são imunes a atordoamento, dano não letal, doença, encantamento, fadiga, frio, ilusão, paralisia, sono e veneno. Eles desaparecem quando são reduzidos a 0 PV ou no fim da cena.' },
  { id: 'controlar-fogo', name: 'Controlar Fogo', circle: 2, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Curto', target: 'veja texto', duration: 'Cena', resistance: '', description: 'Você pode criar, moldar, mover ou extinguir chamas e emanações de calor. Ao lançar a magia, escolha um dos efeitos. Chamejar: o alvo é armas escolhidas, que causam +1d6 de dano de fogo (também afeta armas naturais e ataques desarmados). Esquentar: o alvo é 1 objeto, que começa a esquentar. Ele sofre 1d6 pontos de dano de fogo por rodada e causa o mesmo dano a qualquer criatura que o esteja segurando ou vestindo. Uma criatura pode gastar uma ação completa para resfriar o objeto e cancelar o efeito da magia.' },
  { id: 'controlar-madeira', name: 'Controlar Madeira', circle: 2, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Médio', target: '1 objeto de madeira Grande ou menor', duration: 'Cena', resistance: '', description: 'Você molda, retorce, altera ou repele madeira. Se lançar esta magia num objeto de uma criatura involuntária, ela tem direito a um teste de Vontade para anulá-la. Ao lançar a magia, escolha. Fortalecer: deixa o alvo mais resistente. Armas têm seu dano aumentado em um passo. Escudos têm seu bônus de Defesa aumentado em +2. Esses e outros itens de madeira recebem +5 na RD e dobram seus PV. Modelar: muda a forma do alvo. Pode transformar um galho em espada, criar uma porta onde antes havia apenas uma parede, transformar um tronco em uma caixa... Mas não pode criar mecanismos complexos (como uma besta) ou itens consumíveis.' },
  { id: 'cranio-voador-de-vladislav', name: 'Crânio Voador de Vladislav', circle: 2, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Esta magia cria um crânio envolto em energia negativa. Quando atinge o alvo, ele causa 4d8+4 pontos de dano de trevas e se desfaz emitindo um som horrendo, deixando abalado o alvo e todos os inimigos num raio de 3m dele (criaturas já abaladas ficam apavoradas por 1d4 rodadas). Passar no teste de resistência diminui o dano à metade e evita a condição.' },
  { id: 'desespero-esmagador', name: 'Desespero Esmagador', circle: 2, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Pessoal', target: 'cone de 6m', duration: 'Cena', resistance: 'Vontade parcial', description: 'Humanoides na área são acometidos de grande tristeza, adquirindo as condições fraco e frustrado. Se passarem na resistência, adquirem essas condições por uma rodada.' },
  { id: 'dissipar-magia', name: 'Dissipar Magia', circle: 2, type: 'Universal', school: 'Abjuração', action: 'Padrão', range: 'Médio', target: '1 criatura ou objeto mágico ou esfera com 3m de raio', duration: 'Instantânea', resistance: '', description: 'Você dissipa outras magias que estejam ativas, como se sua duração tivesse acabado. Note que efeitos de magias instantâneas não podem ser dissipados (não se pode dissipar uma Bola de Fogo ou Relâmpago depois que já causaram dano...). Se lançar essa magia em uma criatura ou área, faça um teste de Misticismo; você dissipa as magias com CD igual ou menor que o resultado do teste. Se lançada contra um item mágico, o transforma em um item mundano por 1d6 rodadas (Vontade anula).' },
  { id: 'enxame-de-pestes', name: 'Enxame de Pestes', circle: 2, type: 'Divina', school: 'Convocação', action: 'Completa', range: 'Médio', target: '1 enxame Médio (quadrado de 1,5m)', duration: 'Sustentada', resistance: 'Fortitude reduz à metade', description: 'Você conjura um enxame de criaturas a sua escolha, como besouros, gafanhotos, ratos, morcegos ou serpentes. O enxame pode passar pelo espaço de outras criaturas e não impede que outras criaturas entrem no espaço dele. No final de seus turnos, o enxame causa 2d12 pontos de dano de corte a qualquer criatura em seu espaço (Fortitude reduz à metade). Você pode gastar uma ação de movimento para mover o enxame 12m.' },
  { id: 'esculpir-sons', name: 'Esculpir Sons', circle: 2, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Médio', target: '1 criatura ou objeto', duration: 'Cena', resistance: 'Vontade anula', description: 'Esta magia altera os sons emitidos pelo alvo. Ela não é capaz de criar sons, mas pode omiti-los (como fazer uma carroça ficar silenciosa) ou transformá-los (como fazer uma pessoa ficar com voz de passarinho). Você não pode criar sons que não conhece. Uma vez que escolha a alteração, ela não pode ser mudada. Um conjurador que tenha a voz modificada drasticamente não poderá lançar magias.' },
  { id: 'fisico-divino', name: 'Físico Divino', circle: 2, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você fortalece o corpo do alvo. Ele recebe +2 em Força, Destreza ou Constituição, a sua escolha. Esse aumento não oferece PV ou PM adicionais.' },
  { id: 'flecha-acida', name: 'Flecha Ácida', circle: 2, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: '1 criatura ou objeto', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Você dispara um projétil que causa 4d6 pontos de dano de ácido. Se falhar no teste de resistência, o alvo fica coberto por um muco corrosivo, sofrendo mais 2d6 de dano de ácido no início de seus dois próximos turnos. Se lançada contra um objeto que não esteja em posse de uma criatura a magia causa dano dobrado e ignora a RD do objeto.' },
  { id: 'invisibilidade', name: 'Invisibilidade', circle: 2, type: 'Arcana', school: 'Ilusão', action: 'Livre', range: 'Pessoal', target: 'você', duration: 'Rodada', resistance: '', description: 'O alvo fica invisível (incluindo seu equipamento). Um personagem invisível recebe camuflagem total, +10 em testes de Furtividade contra ouvir e criaturas que não possam vê-lo ficam desprevenidas contra seus ataques. A magia termina se o alvo faz uma ação hostil contra uma criatura. Ações contra objetos livres não dissipam a Invisibilidade.' },
  { id: 'ligacao-telepatica', name: 'Ligação Telepática', circle: 2, type: 'Arcana', school: 'Adivinhação', action: 'Padrão', range: 'Toque', target: '2 criaturas voluntárias', duration: 'Dia', resistance: '', description: 'Você cria um elo mental entre duas criaturas com Inteligência 3 ou maior (você pode ser uma delas). As criaturas podem se comunicar independente de idioma ou distância, mas não em mundos diferentes.' },
  { id: 'localizacao', name: 'Localização', circle: 2, type: 'Arcana', school: 'Adivinhação', action: 'Padrão', range: 'Pessoal', target: 'esfera com 90m de raio', duration: 'Cena', resistance: '', description: 'Esta magia pode encontrar uma criatura ou objeto a sua escolha. Você pode pensar em termos gerais ("um elfo", "algo de metal") ou específicos ("Gwen, a elfa", "uma espada longa"). A magia indica a direção e distância da criatura ou objeto mais próximo desse tipo, caso esteja ao alcance. Você pode movimentar-se para continuar procurando. Esta magia pode ser bloqueada por uma fina camada de chumbo.' },
  { id: 'mapear', name: 'Mapear', circle: 2, type: 'Arcana', school: 'Adivinhação', action: 'Padrão', range: 'Toque', target: 'superfície ou objeto plano, como uma mesa ou papel', duration: 'Cena', resistance: '', description: 'Uma fagulha percorre a superfície afetada, queimando-a enquanto esboça um mapa da região onde o conjurador está. Se você conhece o lugar, o mapa será completo. Caso contrário, apresentará apenas um esboço geral, além de um ponto de referência e um lugar de interesse, ambos definidos pelo mestre. A região representada no mapa tem tamanho máximo de um quadrado de 10km de lado.' },
  { id: 'marca-da-obediencia', name: 'Marca da Obediência', circle: 2, type: 'Universal', school: 'Encantamento', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: 'Vontade anula', description: 'Você toca uma criatura, gravando uma marca mística no corpo dela enquanto profere uma ordem, como "não ataque a mim ou meus aliados", "siga-me" ou "não saia desta sala". A criatura deve seguir essa ordem, gastando todas as ações de seu turno para isso. A ordem não pode ser genérica demais, nem forçar o alvo a atos suicidas. A cada rodada, o alvo pode fazer um teste de Vontade. Se passar, a magia é dissipada.' },
  { id: 'mente-divina', name: 'Mente Divina', circle: 2, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você fortalece a mente do alvo. Ele recebe +2 em Inteligência, Sabedoria ou Carisma, a sua escolha. Esse aumento não oferece PV, PM ou perícias adicionais.' },
  { id: 'metamorfose', name: 'Metamorfose', circle: 2, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Você muda sua aparência e forma — incluindo seu equipamento — para qualquer outra criatura, existente ou imaginada. Independentemente da forma escolhida, você recebe +20 em testes de Enganação para disfarce. Características não mencionadas não mudam. Se quiser, pode assumir uma forma humanoide com uma categoria de tamanho acima ou abaixo da sua; nesse caso aplique os modificadores em Furtividade e testes de manobra.' },
  { id: 'miasma-mefitico', name: 'Miasma Mefítico', circle: 2, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Médio', target: 'nuvem com 6m de raio', duration: 'Instantânea', resistance: 'Fortitude (veja texto)', description: 'A área é coberta por emanações letais. Criaturas na área sofrem 5d6 pontos de dano de ácido e ficam enjoadas por 1 rodada. Se passarem na resistência, sofrem metade do dano e não ficam enjoadas.' },
  { id: 'montaria-arcana', name: 'Montaria Arcana', circle: 2, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'criatura conjurada', duration: 'Dia', resistance: '', description: 'Esta magia convoca um parceiro cavalo (ou pônei) de guerra veterano. Sua aparência é de um animal negro com crina e cauda cinzentas e cascos feitos de fumaça, mas você pode mudá-la se quiser. Além dos benefícios normais, a Montaria Arcana pode atravessar terreno difícil sem redução em seu deslocamento. Você pode usar Misticismo no lugar de Cavalgar para efeitos desta montaria.' },
  { id: 'oracao', name: 'Oração', circle: 2, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: 'todas as criaturas (veja texto)', duration: 'Sustentada', resistance: '', description: 'Você e os seus aliados no alcance recebem +2 em testes de perícia e rolagens de dano, e todos os seus inimigos no alcance sofrem –2 em testes de perícia e rolagens de dano. Esse efeito é cumulativo com outras magias. Componente material: T$ 25 por PM gasto em incensos ou outras oferendas.' },
  { id: 'purificacao', name: 'Purificação', circle: 2, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: '', description: 'Você purifica a criatura tocada, removendo uma condição dela entre abalado, apavorado, alquebrado, atordoado, cego, confuso, debilitado, enjoado, envenenado, esmorecido, exausto, fascinado, fatigado, fraco, frustrado, lento, ofuscado, paralisado, pasmo ou surdo.' },
  { id: 'raio-solar', name: 'Raio Solar', circle: 2, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'linha', duration: 'Instantânea', resistance: 'Reflexos (veja texto)', description: 'Você canaliza uma poderosa rajada de energia positiva que ilumina o campo de batalha. Criaturas na área sofrem 4d8 pontos de dano de luz (ou 4d12, se forem mortos-vivos) e ficam ofuscadas por uma rodada. Se passarem na resistência, sofrem metade do dano e não ficam ofuscadas.' },
  { id: 'refugio', name: 'Refúgio', circle: 2, type: 'Arcana', school: 'Abjuração', action: 'Completa', range: 'Curto', target: 'domo com 6m de raio', duration: 'Dia', resistance: '', description: 'Esta magia cria um domo imóvel e quase opaco por fora, mas transparente pelo lado de dentro. Ele protege contra calor, frio e forças pequenas, mas não contra qualquer coisa capaz de causar dano. Assim, o domo protege contra neve e vento comuns, mas não contra uma flecha ou Bola de Fogo. Porém, como o domo é quase opaco, qualquer criatura dentro dele tem camuflagem total contra ataques vindos de fora. Criaturas podem entrar e sair do domo livremente. Descansar dentro do Refúgio concede recuperação normal de PV e PM.' },
  { id: 'relampago', name: 'Relâmpago', circle: 2, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'linha', duration: 'Instantânea', resistance: 'Reflexos reduz à metade', description: 'Você dispara um poderoso raio que causa 6d6 pontos de dano de eletricidade em todas as criaturas e objetos livres na área.' },
  { id: 'rogar-maldicao', name: 'Rogar Maldição', circle: 2, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Sustentada', resistance: 'Fortitude anula', description: 'Você entoa cânticos maléficos que amaldiçoam uma vítima, criando efeitos variados. Ao lançar a magia, escolha entre os seguintes. Debilidade: o alvo fica esmorecido e não pode se comunicar ou lançar magias. Doença: muda a duração para instantânea. O alvo contrai uma doença a sua escolha, que o afeta imediatamente. Fraqueza: o alvo fica debilitado e lento. Isolamento: o alvo perde o uso de um de seus cinco sentidos a sua escolha.' },
  { id: 'runa-de-protecao', name: 'Runa de Proteção', circle: 2, type: 'Universal', school: 'Abjuração', action: '1 hora', range: 'Toque', target: 'uma área de 6m de raio', duration: 'Cena', resistance: 'varia (veja o texto)', description: 'Você escreve uma runa pessoal em uma superfície fixa, como uma parede ou o chão, que protege uma pequena área ao redor. Quando uma criatura entra na área afetada a runa explode, causando 6d6 pontos de dano em todos os alvos a até 6m. A criatura que ativa a runa não tem direito a teste de resistência; outras criaturas na área têm direito a um teste de Reflexos para reduzir o dano à metade. Quando lança a magia, você escolhe o tipo de dano, entre ácido, eletricidade, fogo, frio, luz ou trevas.' },
  { id: 'salto-dimensional', name: 'Salto Dimensional', circle: 2, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'você', duration: 'Instantânea', resistance: '', description: 'Esta magia transporta você para outro lugar dentro do alcance. Você não precisa perceber nem ter linha de efeito ao seu destino, podendo simplesmente imaginá-lo. Por exemplo, pode se transportar 3m adiante para ultrapassar uma porta fechada. Uma vez transportadas, criaturas não podem agir até a rodada seguinte. Esta magia não permite que você apareça dentro de um corpo sólido; se o ponto de chegada não tem espaço livre, você ressurge na área vazia mais próxima.' },
  { id: 'servos-invisiveis', name: 'Servos Invisíveis', circle: 2, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Longo', target: 'criaturas conjuradas', duration: 'Cena', resistance: '', description: 'Você cria até três servos invisíveis e silenciosos, capazes de realizar tarefas simples como apanhar lenha, colher frutos, varrer o chão ou alimentar um cavalo. Eles também podem ajudá-lo em tarefas mais complexas, como fazer uma pesquisa ou preparar uma poção, mas isso consome sua energia mágica. Você pode "gastar" um servo para receber um bônus não cumulativo de +2 em um teste de perícia (exceto testes de ataque e resistência).' },
  { id: 'silencio', name: 'Silêncio', circle: 2, type: 'Divina', school: 'Ilusão', action: 'Padrão', range: 'Médio', target: 'esfera com 6m de raio', duration: 'Sustentada', resistance: '', description: 'Um silêncio sepulcral recai sobre a área e nenhum som é produzido nela. Enquanto estiverem na área, todas as criaturas ficam surdas. Além disso, como lançar magias exige palavras mágicas, normalmente nenhuma magia pode ser lançada dentro da área.' },
  { id: 'soco-de-arsenal', name: 'Soco de Arsenal', circle: 2, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Ninguém sabe se Mestre Arsenal foi realmente o criador desta magia — mas ele foi o primeiro a utilizá-la. Você fecha o punho e gesticula como se estivesse golpeando o alvo, causando dano de impacto igual a 4d6 + sua Força. A vítima é empurrada 3m na direção oposta à sua. Passar no teste de resistência reduz o dano à metade e evita o empurrão.' },
  { id: 'sopro-das-uivantes', name: 'Sopro das Uivantes', circle: 2, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'cone de 9m', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Você sopra ar gélido que causa 4d6 pontos de dano de frio (Fortitude reduz à metade). Criaturas de tamanho Médio ou menor que falhem na resistência ficam caídas e são empurradas 6m na direção oposta. Se houver uma parede ou outro objeto sólido (mas não uma criatura) no caminho, a criatura para de se mover, mas sofre +2d6 pontos de dano de impacto.' },
  { id: 'sussurros-insanos', name: 'Sussurros Insanos', circle: 2, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 humanoide', duration: 'Cena', resistance: 'Vontade anula', description: 'Você murmura palavras desconexas que afetam a mente do alvo. O alvo fica confuso.' },
  { id: 'tempestade-divina', name: 'Tempestade Divina', circle: 2, type: 'Divina', school: 'Evocação', action: 'Completa', range: 'Longo', target: 'cilindro com 15m de raio e 15m de altura', duration: 'Sustentada', resistance: '', description: 'Esta magia só pode ser usada em ambientes abertos. A área fica sujeita a um vendaval — ataques à distância sofrem penalidade de –5, chamas são apagadas e névoas são dissipadas. Você também pode gerar chuva (–5 em testes de Percepção), neve (como chuva, e a área se torna terreno difícil) ou granizo (como chuva, mais 1 ponto de dano de impacto por rodada, no início de seus turnos).' },
  { id: 'toque-vampirico', name: 'Toque Vampírico', circle: 2, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude reduz à metade', description: 'Sua mão brilha com energia sombria, causando 6d6 pontos de dano de trevas. Você recupera pontos de vida iguais à metade do dano causado (se causou algum dano).' },
  { id: 'velocidade', name: 'Velocidade', circle: 2, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Sustentada', resistance: '', description: 'O alvo pode realizar uma ação padrão ou de movimento adicional por turno. Esta ação não pode ser usada para lançar magias e ativar engenhocas.' },
  { id: 'vestimenta-da-fe', name: 'Vestimenta da Fé', circle: 2, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 armadura, escudo ou vestuário', duration: 'Dia', resistance: '', description: 'Você fortalece um item, aumentando o bônus de Defesa de uma armadura ou escudo em +2. No caso de um vestuário, ele passa a oferecer +2 na Defesa (não cumulativo com armadura). Os efeitos desta magia contam como um bônus de encanto.' },
  { id: 'voz-divina', name: 'Voz Divina', circle: 2, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Você pode conversar com criaturas de qualquer raça e tipo: animal, construto, espírito, humanoide, monstro ou morto-vivo. Pode fazer perguntas e entende suas respostas, mesmo sem um idioma em comum ou se a criatura não for capaz de falar, mas respeitando os limites da Inteligência dela. A atitude dessas criaturas não é alterada, mas você pode usar a perícia Diplomacia para tentar mudar sua atitude.' },
  // 3º Círculo
  { id: 'ancora-dimensional', name: 'Âncora Dimensional', circle: 3, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Curto', target: '1 criatura ou objeto', duration: 'Cena', resistance: '', description: 'O alvo é envolvido por um campo de força cor de esmeralda que impede qualquer movimento planar. Isso inclui magias de convocação (como Salto Dimensional e Teletransporte), viagens astrais e a habilidade incorpóreo.' },
  { id: 'anular-a-luz', name: 'Anular a Luz', circle: 3, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Pessoal', target: 'esfera com 6m de raio', duration: 'Cena', resistance: '', description: 'Esta magia cria uma onda de escuridão que causa diversos efeitos. Magias de até 3º círculo na área são dissipadas se você passar num teste de Religião contra a CD de cada uma. Seus aliados na área são protegidos por uma aura sombria e recebem +4 na Defesa até o fim da cena. Inimigos na área ficam enjoados por 1d4 rodadas (apenas uma vez por cena). Anular a Luz anula Dispersar as Trevas.' },
  { id: 'banimento', name: 'Banimento', circle: 3, type: 'Divina', school: 'Abjuração', action: '1d3+1 rodadas', range: 'Curto', target: '1 criatura', duration: 'Instantânea', resistance: 'Vontade parcial', description: 'Você expulsa uma criatura não nativa de Arton. Um alvo nativo de outro mundo (como muitos espíritos), é teletransportado de volta para um lugar aleatório de seu mundo de origem. Já um alvo morto-vivo tem sua conexão com as energias negativas rompidas, sendo reduzido a 0 PV. Se passar na resistência, em vez dos efeitos acima, o alvo fica enjoado por 1d4 rodadas. Se você tiver um ou mais itens que se oponham ao alvo de alguma maneira, a CD do teste de resistência aumenta em +2 por item.' },
  { id: 'coluna-de-chamas', name: 'Coluna de Chamas', circle: 3, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Longo', target: 'cilindro com 3m de raio e 30m de altura', duration: 'Instantânea', resistance: 'Reflexos reduz à metade', description: 'Um pilar de fogo sagrado desce dos céus, causando 6d6 pontos de dano de fogo mais 6d6 pontos de dano de luz nas criaturas e objetos livres na área.' },
  { id: 'comunhao-com-a-natureza', name: 'Comunhão com a Natureza', circle: 3, type: 'Divina', school: 'Adivinhação', action: 'Completa', range: 'Pessoal', target: 'você', duration: 'Dia', resistance: '', description: 'Após uma breve união com a natureza local, você obtém informações e intuições sobre a região em que está, numa distância equivalente a um dia de viagem. Você recebe 6d4 dados de auxílio. Enquanto a magia durar, sempre que for realizar um teste de perícia em áreas naturais, você pode gastar 2d4 (mais 2d4 para cada círculo de magias acima do 3º que puder lançar) e adicionar o resultado rolado como bônus no teste. A magia termina se você ficar sem dados.' },
  { id: 'contato-extraplanar', name: 'Contato Extraplanar', circle: 3, type: 'Arcana', school: 'Adivinhação', action: 'Completa', range: 'Pessoal', target: 'você', duration: 'Dia', resistance: '', description: 'Sua mente viaja até outro plano de existência, onde entra em contato com seres extraplanares como gênios e demônios. Você firma um contrato com uma dessas entidades para que o auxilie durante o dia, em troca de se alimentar de seu mana. Quando a magia é lançada, você recebe 6d6 dados de auxílio. Enquanto a magia durar, sempre que for realizar um teste de perícia, você pode gastar 1d6 e adicionar o resultado como bônus no teste. No entanto, sempre que rolar um "6" num desses dados, a entidade "suga" 1 PM de você. A magia termina se você gastar todos os dados, ficar sem PM ou no fim do dia.' },
  { id: 'controlar-agua', name: 'Controlar Água', circle: 3, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Longo', target: 'esfera com 30m de raio', duration: 'Cena', resistance: 'veja texto', description: 'Você controla os movimentos e comportamentos da água. Ao lançar a magia, escolha um dos efeitos abaixo. Congelar: toda a água mundana na área é congelada. Criaturas nadando na área ficam imóveis; escapar exige gastar uma ação padrão e passar num teste de Atletismo ou Acrobacia. Derreter: gelo mundano na área vira água e a magia termina. Enchente: eleva o nível da água mundana na área em até 4,5m. Evaporar: toda a água e gelo mundano na área evaporam instantaneamente e a magia termina.' },
  { id: 'controlar-terra', name: 'Controlar Terra', circle: 3, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Longo', target: '9 cubos com 1,5m de lado', duration: 'Instantânea', resistance: 'veja texto', description: 'Você manipula a densidade e a forma de toda terra, pedra, lama, argila ou areia na área. Ao lançar a magia, escolha. Amolecer: se afetar o teto, uma coluna ou suporte, provoca um desabamento que causa 10d6 pontos de dano de impacto às criaturas na área (Reflexos reduz à metade). Se afetar um piso de terra ou pedra, cria terreno difícil de areia ou argila, respectivamente. Modelar: pode usar pedra ou argila para criar um ou mais objetos simples de tamanho Enorme ou menor (sem mecanismos ou partes móveis).' },
  { id: 'convocacao-instantanea', name: 'Convocação Instantânea', circle: 3, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Ilimitado', target: '1 objeto de até 2 espaços', duration: 'Instantânea', resistance: '', description: 'Você invoca um objeto de qualquer lugar para sua mão. O item deve ter sido previamente preparado com uma runa pessoal sua (ao custo de T$ 5). A magia não funciona se o objeto estiver com outra criatura, mas você saberá onde ele está e quem o está carregando.' },
  { id: 'despertar-consciencia', name: 'Despertar Consciência', circle: 3, type: 'Divina', school: 'Encantamento', action: 'Completa', range: 'Toque', target: '1 animal ou planta', duration: 'Dia', resistance: '', description: 'Você desperta a consciência de um animal ou planta. O alvo se torna um parceiro veterano de um tipo a sua escolha entre ajudante, combatente, fortão, guardião, médico, perseguidor ou vigilante. Se usar esta magia em um parceiro que já possua, o nível de poder de um de seus tipos aumenta em um passo. O alvo se torna uma criatura racional, com Inteligência –1, e pode falar.' },
  { id: 'dificultar-deteccao', name: 'Dificultar Detecção', circle: 3, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura ou objeto', duration: 'Dia', resistance: '', description: 'Esta magia oculta a presença do alvo contra qualquer meio mágico de detecção, inclusive detectar magia. Um conjurador que lance uma magia de adivinhação para detectar a presença ou localização do alvo deve fazer um teste de Vontade. Se falhar, a magia não funciona, mas os PM são gastos mesmo assim. Se for lançada sobre uma criatura, Dificultar Detecção protege tanto a criatura quanto seu equipamento.' },
  { id: 'dispersar-as-trevas', name: 'Dispersar as Trevas', circle: 3, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'esfera com 6m de raio', duration: 'Cena', resistance: '', description: 'Esta magia cria um forte brilho que causa diversos efeitos. Todas as magias de 3º círculo ou menor ativas na área são dissipadas se você passar num teste de Religião contra a CD de cada magia. Seus aliados na área recebem +4 em testes de resistência e redução de trevas 10 até o fim da cena. Inimigos na área ficam cegos por 1d4 rodadas (apenas uma vez por cena). Dispersar as Trevas anula Anular a Luz.' },
  { id: 'enxame-rubro-de-ichabod', name: 'Enxame Rubro de Ichabod', circle: 3, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Médio', target: '1 enxame Grande (quadrado de 3m)', duration: 'Sustentada', resistance: 'Reflexos reduz à metade', description: 'Você conjura um enxame de pequenas criaturas da Tormenta. O enxame pode passar pelo espaço de outras criaturas e não impede que outras criaturas entrem no espaço dele. No final de cada um de seus turnos, o enxame causa 4d12 pontos de dano de ácido a qualquer criatura em seu espaço (Reflexos reduz à metade). Você pode gastar uma ação de movimento para mover o enxame com deslocamento de 12m.' },
  { id: 'erupcao-glacial', name: 'Erupção Glacial', circle: 3, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'quadrado de 6m de lado', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Estacas de gelo irrompem do chão. Criaturas na área sofrem 4d6 de dano de corte, 4d6 de dano de frio e ficam caídas. Passar no teste de Reflexos evita o dano de corte e a queda. As estacas duram pela cena, o que torna a área afetada terreno difícil, e concedem cobertura leve para criaturas dentro da área ou atrás dela. As estacas são destruídas caso sofram qualquer quantidade de dano por fogo mágico.' },
  { id: 'ferver-sangue', name: 'Ferver Sangue', circle: 3, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Sustentada', resistance: 'Fortitude parcial', description: 'O sangue do alvo aquece até entrar em ebulição. Quando a magia é lançada, e no início de cada um de seus turnos, o alvo sofre 4d8 pontos de dano de fogo e fica enjoado por uma rodada (Fortitude reduz o dano à metade e evita a condição). Se o alvo passar em dois testes de Fortitude seguidos, dissipa a magia. Se o alvo for reduzido a 0 PV pelo dano desta magia, seu corpo explode, causando 6d6 pontos de dano de fogo em todas as criaturas a até 3m (Reflexos reduz à metade). Essa magia não afeta criaturas sem sangue.' },
  { id: 'globo-de-invulnerabilidade', name: 'Globo de Invulnerabilidade', circle: 3, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você é envolto por uma esfera mágica brilhante com 3m de raio, que detém qualquer magia de 2º círculo ou menor. Nenhuma magia pode ser lançada contra um alvo dentro do globo e magias de área não o penetram. No entanto, magias ainda podem ser lançadas de dentro para fora. Efeitos mágicos não são dissipados quando entram na esfera, apenas suprimidos. O globo é imóvel e não tem efeito sobre criaturas ou objetos. Após lançá-lo, você pode entrar ou sair livremente.' },
  { id: 'heroismo', name: 'Heroísmo', circle: 3, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'O alvo recebe +2 em testes de ataque, perícia e resistência. Além disso, recebe um número de pontos de vida temporários igual ao seu nível.' },
  { id: 'ilusao-lacerante', name: 'Ilusão Lacerante', circle: 3, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Médio', target: 'cubo de 9m', duration: 'Sustentada', resistance: 'Vontade anula', description: 'Você cria uma ilusão de algum perigo mortal. Quando a magia é lançada, criaturas na área devem fazer um teste de Vontade; uma falha significa que a criatura acredita que a ilusão é real e sofre 3d6 pontos de dano psíquico não letal. Sempre que uma criatura iniciar seu turno dentro da área, deve repetir o teste de Vontade. Se falhar, sofre o dano novamente. Somente criaturas que falham veem a ilusão.' },
  { id: 'imobilizar', name: 'Imobilizar', circle: 3, type: 'Universal', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 humanoide ou animal', duration: 'Cena', resistance: 'Vontade parcial', description: 'O alvo fica paralisado; se passar na resistência, em vez disso fica lento. A cada rodada, pode gastar uma ação completa para fazer um novo teste de Vontade. Se passar, se liberta do efeito.' },
  { id: 'lanca-ignea-de-aleph', name: 'Lança Ígnea de Aleph', circle: 3, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Esta magia foi desenvolvida pelo mago imortal Aleph Olhos Vermelhos. Ela dispara um projétil de magma contra o alvo, que sofre 4d6 pontos de dano de fogo e 4d6 pontos de dano de perfuração e fica em chamas. As chamas causam 2d6 pontos de dano por rodada, em vez do dano normal. Se passar no teste de resistência, o alvo sofre metade do dano e não fica em chamas. Respingos de rocha incandescente se espalham com a explosão, atingindo todas as criaturas adjacentes ao alvo, que devem fazer um teste de Reflexos. Se falharem, ficam em chamas.' },
  { id: 'lendas-e-historias', name: 'Lendas e Histórias', circle: 3, type: 'Universal', school: 'Adivinhação', action: 'Padrão', range: 'Toque', target: '1 criatura, objeto ou local', duration: 'Sustentada', resistance: '', description: 'Você descobre informações sobre uma criatura, objeto ou local que esteja tocando. O que exatamente você descobre depende do mestre: talvez você não descubra tudo que há para saber, mas ganhe pistas para continuar a investigação. A cada rodada que mantiver a magia, você descobre todas as informações sobre o alvo, como se tivesse passado em todos os testes de Conhecimento para tal, e todas as habilidades do alvo.' },
  { id: 'manto-de-sombras', name: 'Manto de Sombras', circle: 3, type: 'Universal', school: 'Ilusão', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você fica coberto por um manto de energia sombria. Nesta forma, torna-se incorpóreo: só pode ser afetado por armas e habilidades mágicas, ou por outras criaturas incorpóreas, e pode atravessar objetos sólidos, mas não manipulá-los. Também não pode atacar criaturas normais (mas ainda pode lançar magias nelas). Você fica vulnerável à luz direta: se exposto a uma fonte de luz, sofre 1 ponto de dano por rodada. Você pode gastar uma ação de movimento e 1 PM para "entrar" em uma sombra do seu tamanho ou maior e se teletransportar para outra sombra em alcance médio.' },
  { id: 'miragem', name: 'Miragem', circle: 3, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Longo', target: 'cubo de até 90m de lado', duration: 'Dia', resistance: 'Vontade desacredita', description: 'Você faz um terreno parecer outro, incluindo sons e cheiros. Uma planície pode parecer um pântano, uma floresta pode parecer uma montanha etc. Esta magia pode ser usada para criar armadilhas: areia movediça pode parecer terra firme ou um precipício pode parecer um lago. Você pode alterar, incluir e esconder estruturas dentro da área, mas não criaturas.' },
  { id: 'missao-divina', name: 'Missão Divina', circle: 3, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Dia', resistance: 'Vontade anula (veja texto)', description: 'Esta magia obriga o alvo a cumprir uma tarefa a sua escolha. Ela dura uma semana ou até o alvo cumprir a tarefa, o que vier primeiro. O alvo pode recusar a missão — mas, no fim de cada dia em que não se esforçar para cumprir a tarefa, deve fazer um teste de Vontade; se falhar, sofre uma penalidade cumulativa de –2 em todos os testes e rolagens. A Missão Divina não pode forçar um ato suicida, nem uma missão impossível.' },
  { id: 'muralha-elemental', name: 'Muralha Elemental', circle: 3, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'muralha de energia', duration: 'Cena', resistance: 'veja texto', description: 'Uma muralha de um elemento a sua escolha se eleva da terra. Ela pode ser um muro de até 30m de comprimento e 3m de altura (ou o contrário) ou uma cúpula de 3m de raio. Os efeitos variam conforme o elemento escolhido (fogo, gelo, etc.). Por exemplo, uma muralha de fogo emite ondas de calor que causam 2d6 pontos de dano de fogo em criaturas a até 6m, e atravessá-la causa 8d6 pontos de dano de fogo.' },
  { id: 'pele-de-pedra', name: 'Pele de Pedra', circle: 3, type: 'Universal', school: 'Transmutação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Sua pele ganha aspecto e dureza de rocha. Você recebe redução de dano 5.' },
  { id: 'poeira-da-podridao', name: 'Poeira da Podridão', circle: 3, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Médio', target: 'nuvem com 6m de raio', duration: 'Cena', resistance: 'Fortitude (veja texto)', description: 'Você manifesta uma nuvem de poeira carregada de energia negativa, que apodrece lentamente as criaturas na área. Ao lançar a magia, e no início de seus turnos, criaturas na área sofrem 2d8+8 pontos de dano de trevas (Fortitude reduz à metade). Alvos que falharem no teste não podem recuperar PV por uma rodada.' },
  { id: 'potencia-divina', name: 'Potência Divina', circle: 3, type: 'Divina', school: 'Transmutação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você canaliza o poder de sua divindade. Você aumenta uma categoria de tamanho (seu equipamento muda de acordo) e recebe Força +4 e RD 10. Você não pode lançar magias enquanto estiver sob efeito de Potência Divina.' },
  { id: 'protecao-contra-magia', name: 'Proteção contra Magia', circle: 3, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você protege o alvo contra efeitos mágicos nocivos. O alvo recebe +5 em testes de resistência contra magias.' },
  { id: 'selo-de-mana', name: 'Selo de Mana', circle: 3, type: 'Universal', school: 'Encantamento', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: 'Vontade parcial', description: 'Seu toque manifesta um selo mágico na pele do alvo, que atrapalha o fluxo de mana. Pela duração da magia, sempre que o alvo realizar qualquer ação que gaste PM, deve fazer um teste de Vontade; se passar, faz a ação normalmente. Se falhar, a ação não tem efeito (mas os PM são gastos mesmo assim).' },
  { id: 'servo-divino', name: 'Servo Divino', circle: 3, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'criatura conjurada', duration: 'Cena', resistance: '', description: 'Você pede a sua divindade que envie um espírito para ajudá-lo. Esse espírito realiza uma tarefa a sua escolha que possa ser cumprida em até uma hora. A magia é descarregada quando a criatura cumpre a tarefa, retornando a seu plano natal. O tipo de criatura é escolhido pelo mestre, de acordo com as necessidades da tarefa. Componente material: um pagamento de T$ 100 ao espírito.' },
  { id: 'servo-morto-vivo', name: 'Servo Morto-Vivo', circle: 3, type: 'Universal', school: 'Necromancia', action: 'Completa', range: 'Toque', target: '1 cadáver', duration: 'Instantânea', resistance: '', description: 'Esta magia transforma o cadáver de um humanoide, animal ou monstro em um esqueleto ou zumbi (conforme o estado de conservação do corpo). O morto-vivo então obedece a todos os seus comandos, mesmo suicidas. Se quiser que o morto-vivo o acompanhe, ele funciona como um parceiro iniciante. Uma vez por rodada, quando sofre dano, você pode sacrificar um servo morto-vivo e evitar esse dano. Componente material: um ônix negro (T$ 100), inserido na boca ou olho do cadáver.' },
  { id: 'sopro-da-salvacao', name: 'Sopro da Salvação', circle: 3, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'cone de 9m', duration: 'Instantânea', resistance: '', description: 'Você enche seus pulmões de luz e energia positiva e sopra um cone de poeira reluzente. O sopro afeta apenas seus aliados na área, curando 2d8+4 pontos de vida e removendo uma das seguintes condições de todos os alvos: abalado, atordoado, apavorado, alquebrado, cego, confuso, debilitado, enfeitiçado, enjoado, esmorecido, exausto, fascinado, fatigado, fraco, frustrado, lento, paralisado, pasmo e surdo.' },
  { id: 'telecinesia', name: 'Telecinesia', circle: 3, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Médio', target: 'veja texto', duration: 'Cena', resistance: '', description: 'Você move objetos ou criaturas se concentrando. Ao lançar a magia, escolha. Força Contínua: você move uma criatura Média ou menor, ou objeto de até 10 espaços, a até 6m por rodada. Uma criatura pode anular o efeito sobre ela passando num teste de Vontade. Duração: sustentada. Empurrão Violento: a energia mágica é expelida de uma única vez e arremessa até 10 objetos (no máximo 10 espaços), que podem ser arremessados até o alcance da magia.' },
  { id: 'teletransporte', name: 'Teletransporte', circle: 3, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Toque', target: 'até 5 criaturas voluntárias', duration: 'Instantânea', resistance: '', description: 'Esta magia transporta os alvos para um lugar a sua escolha a até 1.000km. Você precisa fazer um teste de Misticismo, com dificuldade que depende de seu conhecimento sobre o local de destino: CD 20 para um lugar familiar; CD 30 para um lugar conhecido; CD 40 para um lugar que só conhece por descrição. Você não pode se teletransportar para um lugar que nunca visitou sem a descrição de alguém. Se passar no teste, os alvos chegam ao lugar desejado.' },
  { id: 'tentaculos-de-trevas', name: 'Tentáculos de Trevas', circle: 3, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Médio', target: 'esfera com 6m de raio', duration: 'Cena', resistance: '', description: 'Um círculo de energias sombrias se abre no chão, de onde surgem tentáculos feitos de treva viscosa. Ao lançar a magia e no início de cada um de seus turnos, você faz um teste da manobra agarrar (usando seu bônus de Misticismo) contra cada criatura na área. Se você passar, a criatura é agarrada; se a vítima já está agarrada, é esmagada, sofrendo 4d6 pontos de dano de trevas. A área conta como terreno difícil. Os tentáculos são imunes a dano.' },
  { id: 'transformacao-de-guerra', name: 'Transformação de Guerra', circle: 3, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você se torna uma máquina de combate, ficando mais forte, rápido e resistente. Você recebe +6 na Defesa, testes de ataque e rolagens de dano corpo a corpo, e 30 PV temporários. Durante a Transformação de Guerra você não pode lançar magias, mas se torna proficiente em todas as armas.' },
  { id: 'viagem-arborea', name: 'Viagem Arbórea', circle: 3, type: 'Divina', school: 'Convocação', action: 'Completa', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Como parte da execução, você entra em uma árvore adjacente que seja maior do que você. Você pode permanecer dentro da árvore, percebendo os arredores de forma normal (mas sem poder fazer ações). Você pode gastar uma ação de movimento para sair dessa árvore, ou de qualquer outra dentro de 1km. Se estiver dentro de uma árvore que seja destruída, a magia termina e você sofre 10d6 pontos de dano de impacto.' },
  { id: 'videncia', name: 'Vidência', circle: 3, type: 'Universal', school: 'Adivinhação', action: 'Completa', range: 'Ilimitado', target: '1 criatura', duration: 'Sustentada', resistance: 'Vontade anula', description: 'Através de uma superfície reflexiva (bacia de água benta para clérigos, lago para druidas, bola de cristal para magos, espelho para feiticeiros etc.) você pode ver e ouvir uma criatura escolhida e seus arredores (cerca de 6m em qualquer direção), mesmo que ela se mova. O alvo pode estar a qualquer distância, mas se passar em um teste de Vontade, a magia falha. A vítima recebe bônus ou penalidades em seu teste de resistência, dependendo do conhecimento que você tiver dela.' },
  { id: 'voo', name: 'Voo', circle: 3, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Você recebe deslocamento de voo 12m. Voar por meio desta magia é simples como andar — você pode atacar e lançar magias normalmente enquanto voa. Quando a magia termina, você desce lentamente até o chão, como se estivesse sob efeito de Queda Suave.' },
  // 4º Círculo
  { id: 'alterar-memoria', name: 'Alterar Memória', circle: 4, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: 'Vontade anula', description: 'Você invade a mente do alvo e altera ou apaga suas memórias da última hora.' },
  { id: 'animar-objetos', name: 'Animar Objetos', circle: 4, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Médio', target: 'até 8 objetos Minúsculos ou Pequenos, 4 objetos Médios, 2 objetos Grandes ou 1 objeto Enorme', duration: 'Cena', resistance: '', description: 'Você concede vida a objetos inanimados. Cada objeto se torna um parceiro sob seu controle. O tipo dele é escolhido da lista de tamanho e ele não conta em seu limite de parceiros. Com uma ação de movimento, você pode comandar mentalmente qualquer objeto animado dentro do alcance para que auxilie você ou outra criatura. Objetos animados são construtos com valores de Força, Destreza e PV de acordo com seu tamanho. Todos os outros atributos são nulos. Diferente de parceiros comuns, um objeto pode ser alvo de um ataque direto.' },
  { id: 'assassino-fantasmagorico', name: 'Assassino Fantasmagórico', circle: 4, type: 'Arcana', school: 'Necromancia', action: 'Padrão', range: 'Longo', target: '1 criatura', duration: 'Cena', resistance: 'Vontade anula, Fortitude parcial', description: 'Usando os medos subconscientes do alvo, você cria uma imagem daquilo que ele mais teme. Apenas a própria vítima pode ver o Assassino Fantasmagórico com nitidez; outras criaturas presentes enxergam apenas um espectro sombrio. Quando você lança a magia, o espectro surge adjacente a você e a vítima faz um teste de Vontade. Se ela passar, percebe que o espectro é uma ilusão e a magia é dissipada. Se falhar, acredita na existência do espectro, que então flutua 18m por rodada em direção à vítima. Ele é incorpóreo e imune a magias (exceto magias que dissipam outras).' },
  { id: 'campo-antimagia', name: 'Campo Antimagia', circle: 4, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você é cercado por uma barreira invisível com 3m de raio que o acompanha. Qualquer habilidade mágica ou item mágico que entre na área da barreira é suprimida enquanto estiver lá. Criaturas convocadas que entrem em um Campo Antimagia desaparecem, reaparecendo na mesma posição quando o Campo termina. Criaturas mágicas não são diretamente afetadas, mas não poderão usar magias ou habilidades mágicas dentro dele.' },
  { id: 'circulo-da-restauracao', name: 'Círculo da Restauração', circle: 4, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Curto', target: 'esfera com 3m de raio', duration: 'Rodada', resistance: '', description: 'Você evoca um círculo de luz que emana uma energia poderosa. Qualquer criatura viva que termine o turno dentro do círculo recupera 3d8+3 PV e 1 PM. Mortos-vivos e criaturas que sofrem dano por luz perdem PV e PM na mesma quantidade. Uma criatura pode recuperar no máximo 5 PM por dia com esta magia.' },
  { id: 'colera-de-azgher', name: 'Cólera de Azgher', circle: 4, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Médio', target: 'esfera com 6m de raio', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Você cria um fulgor dourado e intenso. Criaturas na área ficam cegas por 1d4 rodadas e em chamas, e sofrem 10d6 pontos de dano de fogo (mortos-vivos sofrem 10d8 pontos de dano). Uma criatura que passe no teste de resistência não fica cega nem em chamas e sofre metade do dano.' },
  { id: 'conceder-milagre', name: 'Conceder Milagre', circle: 4, type: 'Divina', school: 'Encantamento', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você transfere um pouco de seu poder divino a outra criatura. Escolha uma magia de até 2º círculo que você conheça; o alvo pode lançar essa magia uma vez, sem pagar o custo dela em PM (aprimoramentos podem ser usados, mas o alvo deve gastar seus próprios PM). Você sofre uma penalidade de –3 PM até que o alvo lance a magia.' },
  { id: 'conjurar-elemental', name: 'Conjurar Elemental', circle: 4, type: 'Arcana', school: 'Convocação', action: 'Completa', range: 'Médio', target: 'parceiro elemental', duration: 'Sustentada', resistance: '', description: 'Esta magia transforma uma porção de um elemento inerte em uma criatura elemental Grande do tipo do elemento alvo. Por exemplo, lançar esta magia numa fogueira ou tocha cria um elemental do fogo. Você pode criar elementais do ar, água, fogo e terra. O elemental obedece a todos os seus comandos e pode funcionar como um parceiro do tipo destruidor e mais um tipo, ambos mestres. O elemental auxilia apenas você e não conta em seu limite de parceiros.' },
  { id: 'controlar-a-gravidade', name: 'Controlar a Gravidade', circle: 4, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Médio', target: 'cubo de 12m de lado', duration: 'Sustentada', resistance: '', description: 'Você controla os efeitos da gravidade dentro da área. Ao lançar a magia, escolha um dos efeitos abaixo. Aumentar: no início de seus turnos, cada criatura na área deve fazer um teste de Atletismo. Se passar, fica fatigada. Se falhar, fica fatigada e caída. Inverter: inverte a gravidade da área, fazendo com que criaturas e objetos "caiam" para cima, atingindo o topo (12m) em uma rodada. Se um obstáculo impedir o movimento, elas sofrem 1d6 pontos de dano de impacto para cada 1,5m de "queda".' },
  { id: 'controlar-o-clima', name: 'Controlar o Clima', circle: 4, type: 'Divina', school: 'Transmutação', action: 'Completa', range: '2km', target: 'esfera com 2km de raio', duration: 'Cena', resistance: '', description: 'Você muda o clima da área onde se encontra, podendo criar qualquer condição climática: chuva, neve, ventos, névoas... Veja o Capítulo 6: O Mestre para os efeitos do clima.' },
  { id: 'cupula-de-repulsao', name: 'Cúpula de Repulsão', circle: 4, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: 'Vontade anula', description: 'Uma cúpula de energia invisível o cerca, impedindo a aproximação de certas criaturas. Escolha um tipo de criatura ou uma raça de humanoides. Criaturas do grupo escolhido que tentem se aproximar a menos de 3m de você devem fazer um teste de Vontade. Se falharem, não conseguem, gastam a ação e só podem tentar novamente na rodada seguinte. Isso impede ataques corpo a corpo, mas não ataques à distância. Se você tentar se aproximar além do limite de 3m, rompe a cúpula e a magia é dissipada.' },
  { id: 'desintegrar', name: 'Desintegrar', circle: 4, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Médio', target: '1 criatura ou objeto', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Você dispara um raio fino e esverdeado que causa 10d12 pontos de dano de essência. Se o alvo passar no teste de resistência, em vez disso sofre 2d12 pontos de dano. Independentemente do resultado do teste de Fortitude, se os PV do alvo forem reduzidos a 0 ou menos, ele será completamente desintegrado, restando apenas pó.' },
  { id: 'duplicata-ilusoria', name: 'Duplicata Ilusória', circle: 4, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Médio', target: 'cópia ilusória', duration: 'Cena', resistance: '', description: 'Você cria uma cópia ilusória semirreal de você mesmo. Ela é idêntica em aparência, som e cheiro, mas é intangível. A cada turno, você escolhe se verá e ouvirá através da duplicata ou de seu corpo original. A cópia reproduz todas as suas ações, incluindo fala. Qualquer magia com alcance de toque ou maior que você lançar pode se originar da duplicata. Qualquer criatura que interagir com a cópia tem direito a um teste de Vontade para perceber que é uma ilusão.' },
  { id: 'explosao-caleidoscopica', name: 'Explosão Caleidoscópica', circle: 4, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Curto', target: 'esfera com 6m de raio', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Esta magia cria uma forte explosão de luzes estroboscópicas e sons cacofônicos que desorientam as criaturas atingidas. O efeito que cada criatura sofre depende do nível ou ND dela. Nível ou ND 4 ou menor: se falhar, fica inconsciente; se passar, fica atordoada por 1d4 rodadas e enjoada pelo resto da cena. Nível ou ND entre 5 e 9: se falhar, fica atordoada por 1d4 rodadas e enjoada pelo resto da cena. Nível ou ND 10 ou maior: se falhar, fica atordoada por 1 rodada e enjoada por 1d4 rodadas.' },
  { id: 'forma-eterea', name: 'Forma Etérea', circle: 4, type: 'Arcana', school: 'Transmutação', action: 'Completa', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você e todo o equipamento que está com você são transportados para o plano etéreo, que existe paralelamente ao plano material. Na prática, é como ser transformado em um fantasma (mas você ainda é considerado uma criatura viva). Uma criatura etérea é invisível, incorpórea e capaz de se mover em qualquer direção, inclusive para cima e para baixo. Ela enxerga o plano material, mas tudo parece cinza e insubstancial, reduzindo o alcance da visão e audição para 18m. Magias de abjuração e essência afetam criaturas etéreas, mas outras magias, não.' },
  { id: 'guardiao-divino', name: 'Guardião Divino', circle: 4, type: 'Divina', school: 'Convocação', action: 'Padrão', range: 'Curto', target: 'elemental de luz invocado', duration: 'Cena', resistance: '', description: 'A magia invoca um elemental Pequeno, com a forma de um orbe feito de luz divina. A criatura é incorpórea, imune a dano e ilumina como uma tocha. O elemental tem 100 pontos de luz. Uma vez por rodada, durante o seu turno, o elemental pode se movimentar (deslocamento de voo 18m) e gastar quantos pontos de luz quiser para curar dano ou condições de criaturas em alcance curto, à taxa de 1 PV por 1 ponto de luz ou uma condição por 3 pontos de luz.' },
  { id: 'libertacao', name: 'Libertação', circle: 4, type: 'Universal', school: 'Abjuração', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Cena', resistance: '', description: 'O alvo fica imune a efeitos de movimento e ignora qualquer efeito que impeça ou restrinja seu deslocamento. Por fim, pode usar habilidades que exigem liberdade de movimentos mesmo se estiver usando armadura ou escudo.' },
  { id: 'ligacao-sombria', name: 'Ligação Sombria', circle: 4, type: 'Divina', school: 'Necromancia', action: 'Padrão', range: 'Longo', target: '1 criatura', duration: 'Dia', resistance: 'Fortitude anula', description: 'Cria uma conexão entre seu corpo e o da criatura alvo, deixando uma marca idêntica na pele de ambos. Enquanto a magia durar, sempre que você sofrer qualquer dano ou condição, o alvo desta magia deve fazer um teste de Fortitude; se falhar, sofre o mesmo dano que você ou adquire a mesma condição. A magia termina se o alvo chegar a 0 pontos de vida.' },
  { id: 'manto-do-cruzado', name: 'Manto do Cruzado', circle: 4, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Sustentada', resistance: '', description: 'Você invoca o poder de sua divindade na forma de um manto de energia que reveste seu corpo. Esta magia tem duas versões, escolhida quando você aprende a magia. Manto de Luz: um manto dourado e luminoso. No início de cada um de seus turnos, você e todos os seus aliados em alcance curto recuperam 2d8 PV. Você recebe imunidade a dano de trevas e seus ataques corpo a corpo causam +2d8 pontos de dano de luz. Manto de Trevas: um manto negro como a noite. No início de cada um de seus turnos, todos os inimigos em alcance curto sofrem 4d8 pontos de dano de trevas. Você cura metade de todo o dano causado pela magia.' },
  { id: 'mao-poderosa-de-talude', name: 'Mão Poderosa de Talude', circle: 4, type: 'Arcana', school: 'Convocação', action: 'Padrão', range: 'Médio', target: 'mão gigante de energia', duration: 'Sustentada', resistance: '', description: 'Esta magia cria uma mão flutuante Grande que sempre se posiciona entre você e um oponente a sua escolha. A mão fornece cobertura leve (+5 na Defesa) contra esse oponente. Nada é capaz de enganar a mão. A mão tem Defesa 20 e PV e resistências iguais aos seus. Com uma ação de movimento, você pode comandar a mão para que o proteja de outro oponente ou para que agarre o oponente (usando o seu Misticismo com um bônus adicional de +10), mantendo-o agarrado.' },
  { id: 'marionete', name: 'Marionete', circle: 4, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Sustentada', resistance: 'Fortitude anula', description: 'Esta magia manipula o sistema nervoso do alvo. Ao sofrer a magia, e no início de cada um de seus turnos, a vítima faz um teste de Fortitude. Se passar, a magia é anulada. Se falhar, todas as suas ações físicas naquele turno estarão sob controle do conjurador. A vítima ainda tem consciência de tudo, podendo ver, ouvir e até falar com certo esforço (mas não para lançar magias). A vítima pode ser manipulada para se movimentar, lutar, usar habilidades de combate... Você precisa de linha de efeito para controlar a vítima.' },
  { id: 'muralha-de-ossos', name: 'Muralha de Ossos', circle: 4, type: 'Universal', school: 'Necromancia', action: 'Padrão', range: 'Médio', target: 'muro de ossos', duration: 'Cena', resistance: '', description: 'Uma parede de ossos se eleva da terra. A parede tem 15m de comprimento, 9m de altura e 1,5m de espessura. Ela pode ter qualquer forma, mas sua base precisa estar sempre tocando o solo. Quando a parede surge, criaturas na área ocupada ou adjacentes sofrem 4d8 pontos de dano de corte e precisam fazer um teste de Reflexos para não ficarem presas no emaranhado de ossos. Uma criatura presa fica agarrada e pode gastar uma ação padrão para fazer um teste de Atletismo para se soltar.' },
  { id: 'premonicao', name: 'Premonição', circle: 4, type: 'Divina', school: 'Adivinhação', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Vislumbres do futuro permitem que você reavalie suas ações. Uma vez por rodada, você pode rolar novamente um teste recém realizado, mas deve aceitar o resultado da nova rolagem.' },
  { id: 'raio-polar', name: 'Raio Polar', circle: 4, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Médio', target: '1 criatura', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Você dispara um raio azul esbranquiçado de gelo e ar congelante. O alvo sofre 10d8 pontos de dano de frio e fica preso em um bloco de gelo (paralisado). Se passar no teste de resistência, sofre metade do dano e, em vez de paralisado, fica lento por uma rodada. É possível quebrar o gelo para libertar uma criatura presa: o bloco tem 20 PV, RD 10 e é vulnerável a fogo. Uma criatura presa pode gastar uma ação completa para fazer um teste de Atletismo e se libertar.' },
  { id: 'relampago-flamejante-de-reynard', name: 'Relâmpago Flamejante de Reynard', circle: 4, type: 'Arcana', school: 'Evocação', action: 'Duas rodadas', range: 'Médio', target: 'bolas de fogo e relâmpagos', duration: 'Sustentada', resistance: 'Reflexos reduz à metade', description: 'Esta é uma magia poderosa, desenvolvida pelo metódico e impassível arquimago Reynard. Você invoca as energias elementais do fogo e do relâmpago, fazendo com que uma de suas mãos fique em chamas e a outra mão eletrificada. Pela duração da magia, você pode gastar uma ação de movimento para disparar uma bola de fogo (10d6 pontos de dano de fogo numa esfera com 6m de raio) ou um relâmpago (10d6 pontos de dano de eletricidade numa linha). Você também pode usar as duas mãos num ataque de energia mista (20d12 pontos de dano, metade de fogo e metade de eletricidade, numa esfera com 9m de raio).' },
  { id: 'sonho', name: 'Sonho', circle: 4, type: 'Arcana', school: 'Adivinhação', action: '10 minutos', range: 'Ilimitado', target: '1 criatura viva', duration: 'Cena', resistance: '', description: 'Você entra nos sonhos de uma criatura. Uma vez lá, pode conversar com ela até que ela acorde. Se o alvo não estiver dormindo quando você lançar a magia, você pode permanecer em transe até que ele adormeça. Durante o transe, você fica indefeso e sem consciência dos arredores. Você pode sair do transe quando quiser, mas a magia termina.' },
  { id: 'talho-invisivel-de-edauros', name: 'Talho Invisível de Edauros', circle: 4, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Pessoal', target: 'cone de 9m', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Esta magia cruel foi desenvolvida pelo mago de combate Edauros. Você faz um gesto rápido e dispara uma lâmina de ar em alta velocidade. Criaturas na área sofrem 10d8 pontos de dano de corte e ficam sangrando. Alvos que passem no teste de resistência sofrem metade do dano e não ficam sangrando.' },
  { id: 'terremoto', name: 'Terremoto', circle: 4, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Longo', target: 'esfera com 30m de raio', duration: 'Rodada', resistance: 'veja texto', description: 'Esta magia cria um tremor de terra que rasga o solo. O terremoto dura uma rodada, durante a qual criaturas sobre o solo ficam atordoadas (apenas uma vez por cena). Barreiras físicas não interrompem a área. O efeito exato depende do terreno. Caverna ou subterrâneo: a magia derruba o teto, causando 12d6 pontos de dano de impacto e agarrando todas as criaturas na área (Reflexos reduz à metade). Construção: todas as estruturas na área sofrem 200 pontos de dano de impacto.' },
  { id: 'viagem-planar', name: 'Viagem Planar', circle: 4, type: 'Universal', school: 'Convocação', action: 'Completa', range: 'Toque', target: 'pessoal', duration: 'Instantânea', resistance: '', description: 'Você viaja instantaneamente para outro plano da Criação. Lá, você chega de 10 a 1.000km do destino pretendido (role 1d100 e multiplique por 10km). Componente material: um bastão de metal precioso em forma de forquilha (no valor de T$ 1.000). O tipo de metal determina para qual plano de existência você será enviado.' },
  { id: 'visao-da-verdade', name: 'Visão da Verdade', circle: 4, type: 'Universal', school: 'Adivinhação', action: 'Movimento', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Você enxerga a forma real das coisas. Você pode ver através de camuflagem e escuridão (normais e mágicas), assim como efeitos de ilusão e transmutação (enxergando a verdade como formas translúcidas ou sobrepostas).' },
  // 5º Círculo
  { id: 'alterar-destino', name: 'Alterar Destino', circle: 5, type: 'Arcana', school: 'Adivinhação', action: 'Reação', range: 'Pessoal', target: 'você', duration: 'Instantânea', resistance: '', description: 'Sua mente visualiza todas as possibilidades de um evento, permitindo a você escolher o melhor curso de ação. Você pode rolar novamente um teste de resistência com um bônus de +10 ou um inimigo deve rolar novamente um ataque contra você com uma penalidade de –10.' },
  { id: 'aprisionamento', name: 'Aprisionamento', circle: 5, type: 'Arcana', school: 'Abjuração', action: 'Completa', range: 'Curto', target: '1 criatura', duration: 'Dia', resistance: 'Vontade anula', description: 'Você cria uma prisão mágica para aprisionar uma criatura. Se falhar no teste de resistência, o alvo sofre o efeito da magia; se passar, fica imune a esta magia por uma semana. Enquanto estiver aprisionada, a criatura não precisa respirar e alimentar-se, e não envelhece. Magias de adivinhação não conseguem localizar ou perceber o alvo. Ao lançar a magia, você escolhe uma das formas de prisão. O componente material varia, mas todos custam T$ 1.000.' },
  { id: 'aura-divina', name: 'Aura Divina', circle: 5, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'esfera com 9m de raio', duration: 'Cena', resistance: 'Vontade parcial', description: 'Você se torna um conduíte da energia de sua divindade, emanando uma aura brilhante. Você e aliados devotos da mesma divindade ficam imunes a encantamento e recebem +10 na Defesa e em testes de resistência. Aliados não devotos da mesma divindade recebem +5 na Defesa e em testes de resistência. Inimigos que entrem na área devem fazer um teste de Vontade; em caso de falha, recebem uma condição a sua escolha entre esmorecido, debilitado ou lento até o fim da cena.' },
  { id: 'barragem-elemental-de-vectorius', name: 'Barragem Elemental de Vectorius', circle: 5, type: 'Arcana', school: 'Evocação', action: 'Padrão', range: 'Longo', target: '4 esferas elementais', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Criada pelo arquimago Vectorius, esta magia produz quatro esferas, de ácido, eletricidade, fogo e frio, que voam até um ponto a sua escolha. Quando atingem o ponto escolhido, explodem causando 6d6 pontos de dano de seu respectivo tipo numa área com 12m de raio. Um teste de Reflexos reduz o dano à metade. Você pode mirar cada esfera em uma criatura ou ponto diferente. Além do dano, as esferas causam efeitos adicionais em criaturas que falharem nos testes de resistência.' },
  { id: 'buraco-negro', name: 'Buraco Negro', circle: 5, type: 'Universal', school: 'Convocação', action: 'Completa', range: 'Longo', target: 'buraco negro', duration: 'Rodada', resistance: 'Fortitude parcial', description: 'Esta magia cria um vácuo capaz de sugar tudo nas proximidades. Escolha um espaço desocupado para o buraco negro. No início de cada um de seus três turnos seguintes, todas as criaturas a até alcance longo do buraco negro, incluindo você, devem fazer um teste de Fortitude. Em caso de falha, ficam caídas e são puxadas 30m na direção do buraco. Objetos soltos também são puxados. Criaturas podem gastar uma ação de movimento para se segurar em algum objeto fixo, recebendo +2 em seus testes de resistência.' },
  { id: 'chuva-de-meteoros', name: 'Chuva de Meteoros', circle: 5, type: 'Arcana', school: 'Convocação', action: 'Completa', range: 'Longo', target: 'quadrado com 18m de lado', duration: 'Instantânea', resistance: 'Reflexos parcial', description: 'Meteoros caem dos céus, devastando a área afetada. Criaturas na área sofrem 15d6 pontos de dano de impacto, 15d6 pontos de dano de fogo e ficam caídas e presas sob os escombros (agarradas). Uma criatura que passe no teste de resistência sofre metade do dano total e não fica caída e agarrada. Toda a área afetada fica coberta de escombros, sendo considerada terreno difícil. Esta magia só pode ser utilizada a céu aberto.' },
  { id: 'controlar-o-tempo', name: 'Controlar o Tempo', circle: 5, type: 'Arcana', school: 'Transmutação', action: 'Padrão', range: 'Curto', target: 'veja texto', duration: 'Cena', resistance: '', description: 'Aquele que controla o tempo controla o mundo. Escolha um dos efeitos a seguir. Congelar o tempo: você gera uma bolha do seu tamanho na qual o tempo passa mais lentamente. Para outras criaturas, a bolha surge e desaparece instantaneamente, mas, para você, ela dura 3 rodadas, durante as quais você pode agir e não é afetado por efeitos contínuos. Durante essas 3 rodadas, você e quaisquer efeitos que você gerar não podem sair da área que você ocupava quando lançou esta magia.' },
  { id: 'deflagracao-de-mana', name: 'Deflagração de Mana', circle: 5, type: 'Arcana', school: 'Evocação', action: 'Completa', range: 'Pessoal', target: 'esfera com 15m de raio', duration: 'Instantânea', resistance: 'Fortitude parcial', description: 'Após concentrar seu mana, você emana energia, como uma estrela em plena terra. Todas as criaturas na área sofrem 150 pontos de dano de essência e todos os itens mágicos (exceto artefatos) tornam-se mundanos. Você não é afetado pela magia. Alvos que passem no teste de Fortitude sofrem metade do dano e seus itens mágicos voltam a funcionar após um dia.' },
  { id: 'desejo', name: 'Desejo', circle: 5, type: 'Arcana', school: 'Transmutação', action: 'Completa', range: 'Veja texto', target: 'veja texto', duration: 'Cena', resistance: 'veja texto', description: 'Esta é a mais poderosa das magias arcanas, permitindo alterar a realidade a seu bel-prazer. Você pode dissipar os efeitos de qualquer magia de 4º círculo ou menor; transportar até 10 criaturas voluntárias em alcance longo para qualquer outro local, em qualquer plano; ou desfazer um acontecimento recente (permite que um teste realizado por uma criatura em alcance longo na última rodada seja realizado novamente). Você pode desejar por algo ainda mais poderoso.' },
  { id: 'engenho-de-mana', name: 'Engenho de Mana', circle: 5, type: 'Arcana', school: 'Abjuração', action: 'Padrão', range: 'Médio', target: 'disco de energia com 1,5m de diâmetro', duration: 'Sustentada', resistance: '', description: 'Você cria um disco de energia que lembra uma roda de engenho e flutua no ponto em que foi conjurado. O disco é imune a dano, não pode ser movido e faz uma contramágica automática contra qualquer magia lançada em alcance médio dele (exceto as suas), usando seu teste de Misticismo. Caso vença o teste, o engenho não só anula a magia como absorve os PM usados para lançá-la, acumulando PM temporários. No seu turno, se estiver ao alcance do disco, você pode gastar PM nele para lançar magias.' },
  { id: 'furia-do-panteao', name: 'Fúria do Panteão', circle: 5, type: 'Divina', school: 'Evocação', action: 'Completa', range: 'Longo', target: 'cubo de 90m', duration: 'Sustentada', resistance: 'veja texto', description: 'Você cria uma nuvem de tempestade violenta. Os ventos tornam ataques à distância impossíveis e fazem a área contar como condição terrível para lançar magia. Inimigos na área têm a visibilidade reduzida. Uma vez por turno, você pode gastar uma ação de movimento para gerar um efeito. Nevasca: inimigos na área sofrem 10d6 pontos de dano de frio (Fortitude reduz à metade). Raios: até 6 inimigos a sua escolha na área sofrem 10d8 pontos de dano de eletricidade (Reflexos reduz à metade). Siroco: transforma a chuva em uma tempestade de areia escaldante.' },
  { id: 'intervencao-divina', name: 'Intervenção Divina', circle: 5, type: 'Divina', school: 'Convocação', action: 'Completa', range: 'Veja texto', target: 'veja texto', duration: 'Cena', resistance: 'veja texto', description: 'Você pede a sua divindade para interceder diretamente. Você pode curar todos os PV e condições de até 10 criaturas em alcance longo (este efeito cura mortos-vivos), ou dissipar os efeitos de qualquer magia de 4º círculo ou menor. Você pode implorar por algo ainda mais poderoso. Nesse caso, a magia requer o sacrifício de 2 PM e pode fazer coisas como criar um item mundano de até T$ 30.000, duplicar os efeitos de qualquer magia de até 4º círculo, ou proteger uma cidade de um desastre.' },
  { id: 'invulnerabilidade', name: 'Invulnerabilidade', circle: 5, type: 'Universal', school: 'Abjuração', action: 'Padrão', range: 'Pessoal', target: 'você', duration: 'Cena', resistance: '', description: 'Esta magia cria uma barreira mágica impenetrável que protege você contra efeitos nocivos mentais ou físicos, a sua escolha. Proteção mental: você fica imune às condições abalado, alquebrado, apavorado, atordoado, confuso, esmorecido, fascinado, frustrado e pasmo, além de efeitos de encantamento e ilusão. Proteção física: você fica imune às condições atordoado, cego, debilitado, enjoado, envenenado, exausto, fatigado, fraco, lento, ofuscado e paralisado, além de acertos críticos, ataques furtivos e doenças.' },
  { id: 'lagrimas-de-wynna', name: 'Lágrimas de Wynna', circle: 5, type: 'Divina', school: 'Abjuração', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Instantânea', resistance: 'Vontade parcial', description: 'Se falhar no teste de resistência, o alvo perde a habilidade de lançar magias arcanas até o fim da cena. Se passar, perde a habilidade por uma rodada.' },
  { id: 'legiao', name: 'Legião', circle: 5, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Médio', target: 'até 10 criaturas na área', duration: 'Sustentada', resistance: 'Vontade parcial', description: 'Você domina a mente dos alvos. Os alvos obedecem cegamente a seus comandos, exceto ordens claramente suicidas. Um alvo tem direito a um teste no final de cada um de seus turnos para se livrar do efeito. Alvos que passarem no teste ficam abalados por 1 rodada enquanto recuperam a consciência.' },
  { id: 'mata-dragao', name: 'Mata-Dragão', circle: 5, type: 'Arcana', school: 'Evocação', action: 'Duas rodadas', range: 'Pessoal', target: 'cone de 30m', duration: 'Instantânea', resistance: 'Reflexos reduz à metade', description: 'Esta é uma das mais poderosas magias de destruição existentes. Após entoar longos cânticos, o conjurador dispara uma carga de energia que varre uma enorme área à sua frente, causando 20d12 pontos de dano de essência em todas as criaturas, construções e objetos livres atingidos. Sempre que rola um resultado 12 em um dado de dano, a magia causa +1d12 pontos de dano. Apesar de seu poder destrutivo, esta magia é lenta, tornando seu uso difícil em combate.' },
  { id: 'palavra-primordial', name: 'Palavra Primordial', circle: 5, type: 'Universal', school: 'Encantamento', action: 'Padrão', range: 'Curto', target: '1 criatura com menos níveis que você', duration: 'Cena', resistance: 'Vontade parcial', description: 'Você pronuncia uma palavra do idioma primordial da Criação, que causa um dos efeitos abaixo, a sua escolha. Atordoar: a criatura fica atordoada por 1d4+1 rodadas (apenas uma vez por cena). Se passar no teste de resistência, ou se já foi atordoada por esta magia, fica desprevenida por 1d4 rodadas. Cegar: a criatura fica cega. Se passar, fica ofuscada por 1d4 rodadas. Matar: a criatura morre. Além do teste de Vontade, a criatura tem direito a um teste de Fortitude se tiver mais da metade de seus PV. Se passar em qualquer um deles, em vez de morrer perde 10d8 pontos de vida e fica sangrando.' },
  { id: 'possessao', name: 'Possessão', circle: 5, type: 'Arcana', school: 'Encantamento', action: 'Padrão', range: 'Longo', target: '1 criatura', duration: 'Dia', resistance: 'Vontade anula', description: 'Você projeta sua consciência no corpo do alvo. Enquanto possuir uma criatura, você assume o controle total do corpo dela. O seu próprio corpo fica inconsciente e a consciência do alvo fica inerte. Em termos de jogo, você continua usando a sua ficha, mas com os atributos físicos e deslocamento da criatura. Se o alvo passar no teste de resistência, sabe que você tentou possuí-lo e fica imune a esta magia por um dia. Caso o corpo da criatura morra enquanto você a possui, você deve fazer um teste de Vontade contra a CD da sua própria magia para retornar ao seu corpo.' },
  { id: 'projetar-consciencia', name: 'Projetar Consciência', circle: 5, type: 'Universal', school: 'Adivinhação', action: 'Padrão', range: 'Ilimitado (veja texto)', target: 'local ou criatura conhecidos', duration: 'Sustentada', resistance: '', description: 'Esta magia faz com que sua consciência deixe seu corpo e se transporte instantaneamente para um local ou para perto de uma criatura alvo. Se escolher um local, ele precisa ser conhecido por você. Se escolher uma criatura, você transporta sua consciência até onde a criatura estiver, contanto que estejam no mesmo plano. Você adquire uma forma fantasmagórica invisível, mas pode se mostrar usando uma ação de movimento. Pode se mover com deslocamento de voo 18m e atravessar objetos sólidos, mas fica limitado aos limites do local ou ao alcance curto da criatura alvo.' },
  { id: 'reanimacao-impura', name: 'Reanimação Impura', circle: 5, type: 'Divina', school: 'Necromancia', action: 'Completa', range: 'Toque', target: '1 criatura', duration: 'Cena', resistance: '', description: 'Você reanima uma criatura morta recentemente (dentro da mesma cena), trazendo sua alma de volta ao corpo de forma forçada. O tipo da criatura muda para morto-vivo, mas ela retém suas memórias e habilidades de quando estava viva, podendo inclusive lançar magias. A criatura pode pensar e falar livremente, mas obedece cegamente a seus comandos. Quando a cena termina, a criatura volta a ficar morta. Se for destruída, a criatura não pode ser reanimada novamente com esta magia.' },
  { id: 'requiem', name: 'Réquiem', circle: 5, type: 'Arcana', school: 'Ilusão', action: 'Completa', range: 'Curto', target: 'criaturas escolhidas', duration: 'Sustentada', resistance: 'Vontade anula', description: 'Esta magia cria uma ilusão particular para cada uma das criaturas que atingir. Enquanto a magia durar, no início de cada um de seus turnos, cada criatura afetada deve fazer um teste de Vontade; se falhar, acha que não tomou as ações que realmente fez no turno anterior e é obrigada a repetir as mesmas ações neste turno, com uma penalidade cumulativa de –5 em todos os testes para cada vez que se repetir.' },
  { id: 'roubar-a-alma', name: 'Roubar a Alma', circle: 5, type: 'Universal', school: 'Necromancia', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Dia', resistance: 'Vontade parcial', description: 'Você rouba a alma da vítima, armazenando-a em um objeto. Se o alvo passar no teste de resistência, sente o impacto de sua alma ser puxada para fora do corpo e fica abalado por 1 rodada. Se falhar, seu corpo fica caído, inconsciente e inerte, enquanto sua alma é transportada para dentro do objeto. O corpo não envelhece nem se decompõe, permanecendo em estase. Ele pode ser atacado e destruído normalmente. O objeto escolhido deve custar T$ 1.' },
  { id: 'segunda-chance', name: 'Segunda Chance', circle: 5, type: 'Divina', school: 'Evocação', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: '', description: 'Um brilho de luz, na forma de asas de fênix, emana do alvo. Ele recupera 200 pontos de vida e se cura de qualquer das seguintes condições: abalado, apavorado, alquebrado, atordoado, cego, confuso, debilitado, enjoado, envenenado, esmorecido, exausto, fascinado, fatigado, fraco, frustrado, lento, ofuscado, paralisado, pasmo ou surdo.' },
  { id: 'semiplano', name: 'Semiplano', circle: 5, type: 'Arcana', school: 'Convocação', action: 'Completa', range: 'Curto', target: 'semiplano com 30m de lado', duration: 'Dia', resistance: '', description: 'Você cria uma dimensão particular. Você pode entrar no semiplano gastando uma ação padrão e 10 PM, desaparecendo do plano material como se tivesse se teletransportado. Você pode levar criaturas voluntárias que esteja tocando, ao custo de 1 PM por criatura extra, e objetos que esteja tocando. Uma vez no semiplano, pode gastar uma ação completa para voltar ao plano material, no mesmo local onde estava.' },
  { id: 'sombra-assassina', name: 'Sombra Assassina', circle: 5, type: 'Arcana', school: 'Ilusão', action: 'Padrão', range: 'Curto', target: '1 criatura', duration: 'Cena', resistance: 'Vontade parcial', description: 'Esta magia cria uma duplicata ilusória do alvo na forma de uma silhueta, ligada a ele como se fosse uma manifestação sólida de sua própria sombra. A duplicata segue automaticamente o alvo. Sempre que o alvo faz uma ação hostil, a sombra imediatamente realiza a mesma ação contra o alvo, usando as mesmas estatísticas e rolagens. A sombra pode ser atacada, tem as mesmas estatísticas do alvo e é destruída quando chega a 0 PV. Se o alvo passar no teste de resistência, a sombra desaparece no final do turno do alvo.' },
  { id: 'toque-da-morte', name: 'Toque da Morte', circle: 5, type: 'Universal', school: 'Necromancia', action: 'Padrão', range: 'Toque', target: '1 criatura', duration: 'Instantânea', resistance: 'veja texto', description: 'Sua mão exala energias letais. A criatura sofre 10d8+10 pontos de dano de trevas. Se estiver com menos da metade de seus PV, em vez disso deve fazer um teste de Fortitude. Se passar, sofre o dano normal. Se falhar, seus PV são reduzidos a –10.' },
]
